    // SECTION 4: ON-DEMAND GENERATION ENGINE (QUADTREE)
    // STRATEGIC JUSTIFICATION: This Quadtree implementation is the heart of the on-demand generation
    // engine. It recursively subdivides space, applying grammar rules to populate newly created
    // regions only when they become visible, thus creating the illusion of an infinite universe.

    const MAX_QUADTREE_DEPTH = 10;
    const MIN_NODE_SIZE_ON_SCREEN = 50; // pixels

    class Quadtree {
        constructor(x, y, size, depth, symbol) {
            this.x = x;
            this.y = y;
            this.size = size;
            this.depth = depth;
            this.symbol = symbol; // Symbol from the grammar
            this.children = null; // To hold four child Quadtrees
            this.isPopulated = false; // Tracks if grammar has been applied
            this.seed = this.calculateSeed();
        }

        // Generates a deterministic seed based on position and depth.
        // This is critical for ensuring the same part of space always generates the same content.
        calculateSeed() {
            // A simple hashing function
            let h1 = 0xdeadbeef, h2 = 0x41c6ce57;
            const s1 = Math.floor(this.x);
            const s2 = Math.floor(this.y);
            const s3 = this.depth;
            h1 = Math.imul(h1 ^ s1, 2654435761);
            h2 = Math.imul(h2 ^ s1, 1597334677);
            h1 = Math.imul(h1 ^ s2, 2654435761);
            h2 = Math.imul(h2 ^ s2, 1597334677);
            h1 = Math.imul(h1 ^ s3, 2654435761);
            h2 = Math.imul(h2 ^ s3, 1597334677);
            return (h1 ^ h2) >>> 0;
        }

        // Applies grammar rules to create children. This is the core of the generation engine.
        populateNode() {
            if (this.isPopulated || this.depth >= MAX_QUADTREE_DEPTH) return;

            const rng = new LCG(this.seed);
            const structure = expandSymbol(this.symbol, rng);

            if (structure) {
                this.children = [];
                const childSize = this.size / 3; // Using 3x3 grid for expansion
