                for (let i = 0; i < 3; i++) {
                    for (let j = 0; j < 3; j++) {
                        const childX = this.x + (j - 1) * childSize;
                        const childY = this.y + (i - 1) * childSize;
                        const childSymbol = structure[structureIndex++];
                        this.children.push(new Quadtree(childX, childY, childSize, this.depth + 1, childSymbol));
