            h1 = Math.imul(h1 ^ s3, 2654435761); h2 = Math.imul(h2 ^ s3, 1597334677);
            return (h1 ^ h2) >>> 0;
        }

        populateNode() {
            if (this.isPopulated || this.depth >= MAX_DEPTH) return;

            const rng = new LCG(this.seed);
            const structure = expandSymbol(this.symbol, rng);

            if (structure) {
                this.children = [];
                const childSize = this.size / 3;
                let structureIndex = 0;
                for (let i = 0; i < 3; i++) {
                    for (let j = 0; j < 3; j++) {
                        const childX = this.x + (j - 1) * childSize;
                        const childY = this.y + (i - 1) * childSize;
                        const childSymbol = structure[structureIndex++];
                        this.children.push(new Ninetree(childX, childY, childSize, this.depth + 1, childSymbol));
