    // STRATEGIC JUSTIFICATION: Ties all components together, handling the continuous rendering loop,
    // updating the view state, and initiating the drawing process from the root node.

    const UNIVERSE_SIZE = 1e9;
    const root = new Ninetree(0, 0, UNIVERSE_SIZE, 0, 'U');

    const zoomLevelUI = document.getElementById('zoom-level');
    const coordsUI = document.getElementById('coords');

    function animate() {
