    // SECTION 1: CORE SYSTEMS AND UTILITIES
    // This section establishes the foundational components required by the generation engine.

    // 1.1: Canvas and Rendering Context Setup
    const canvas = document.getElementById('universeCanvas');
    const ctx = canvas.getContext('2d');

    // Set canvas dimensions to fill the viewport
    let width = window.innerWidth;
    let height = window.innerHeight;
    canvas.width = width;
    canvas.height = height;

    window.addEventListener('resize', () => {
        width = window.innerWidth;
        height = window.innerHeight;
        canvas.width = width;
        canvas.height = height;
    }, false);

    // 1.2: Seedable Pseudo-Random Number Generator (PRNG)
    // JUSTIFICATION: Deterministic generation is crucial for a consistent, explorable universe.
    // Standard `Math.random()` is not seedable. Therefore, a Linear Congruential Generator (LCG) is
    // implemented from first principles. LCG formula: X_{n+1} = (a * X_n + c) mod m
    class LCG {
        constructor(seed) {
            // REFINEMENT: Added comment clarifying parameter origins. These are well-known constants
            // from numerical recipes, chosen for their good statistical properties in a 32-bit integer space.
            this.m = 2**32; // Modulus
            this.a = 1664525; // Multiplier
            this.c = 1013904223; // Increment
            this.state = Math.floor(seed);
        }

        // Returns a pseudo-random integer
        nextInt() {
            this.state = (this.a * this.state + this.c) % this.m;
            return this.state;
        }

        // Returns a pseudo-random float between 0 (inclusive) and 1 (exclusive)
        nextFloat() {
            return this.nextInt() / this.m;
        }
    }

    // 1.3: View and Interaction State
    // JUSTIFICATION: Manages the user's viewport. Manipulated by user input for 'infinite zoom' and panning.
    const view = {
        x: 0,
        y: 0,
        zoom: 1.0,
        targetZoom: 1.0,
        targetX: 0,
        targetY: 0
    };

    let isDragging = false;
    let lastMouseX = 0;
    let lastMouseY = 0;

    canvas.addEventListener('mousedown', (e) => {
        isDragging = true;
        lastMouseX = e.clientX;
        lastMouseY = e.clientY;
    });

    canvas.addEventListener('mouseup', () => { isDragging = false; });
    canvas.addEventListener('mouseleave', () => { isDragging = false; });

    canvas.addEventListener('mousemove', (e) => {
        if (isDragging) {
            const dx = e.clientX - lastMouseX;
            const dy = e.clientY - lastMouseY;
            // Panning speed is inversely proportional to zoom for consistent feel.
            view.targetX -= dx / view.zoom;
            view.targetY -= dy / view.zoom;
            lastMouseX = e.clientX;
            lastMouseY = e.clientY;
        }
    });

    canvas.addEventListener('wheel', (e) => {
        e.preventDefault();
        const zoomFactor = 1.1;
        const mouseX = e.clientX;
        const mouseY = e.clientY;

        // Convert mouse screen coordinates to world coordinates before zoom.
        const worldX = (mouseX - width / 2) / view.zoom + view.x;
        const worldY = (mouseY - height / 2) / view.zoom + view.y;

        if (e.deltaY < 0) { view.targetZoom *= zoomFactor; } 
        else { view.targetZoom /= zoomFactor; }

        // REFINEMENT: Clamp zoom to prevent floating point instability at extreme scales.
        view.targetZoom = Math.max(1e-12, Math.min(1e12, view.targetZoom));

        // Calculate the new world coordinates of the mouse post-zoom and adjust the view
        // center to keep the pre-zoom world coordinates under the mouse, creating a zoom-to-cursor effect.
        const newWorldX = (mouseX - width / 2) / view.targetZoom + view.targetX;
        const newWorldY = (mouseY - height / 2) / view.targetZoom + view.targetY;

        view.targetX += worldX - newWorldX;
        view.targetY += worldY - newWorldY;
    }, { passive: false });


    // SECTION 2: THE HIERARCHICAL GRAMMAR
    // STRATEGIC JUSTIFICATION: This formal grammar defines the universe's structure, enabling
    // complex, hierarchical, and aesthetically controlled procedural generation.

    const GRAMMAR_RULES = {
        // Symbols: U: Universe, C: Cluster, V: Void, G: Galaxy, N: Nebula, S: Star System, E: Empty
        'U': [{ weight: 1.0, structure: 'CVCVCVCVC' }],
        'C': [{ weight: 0.8, structure: 'GEGENGEGE' }, { weight: 0.2, structure: 'GGNVGEGNG' }],
        'V': [{ weight: 0.95, structure: 'EEEEEEEEE' }, { weight: 0.05, structure: 'EEEEGEEEE' }],
        'G': [{ weight: 1.0, structure: 'SESESESES' }],
        'N': [{ weight: 1.0, structure: 'ESEEESEEE' }],
        'S': [], // Terminal symbol
        'E': [], // Terminal symbol
    };

    function expandSymbol(symbol, rng) {
        const rules = GRAMMAR_RULES[symbol];
        if (!rules || rules.length === 0) return null; // Terminal symbol

        const totalWeight = rules.reduce((sum, rule) => sum + rule.weight, 0);
        let random = rng.nextFloat() * totalWeight;

        for (const rule of rules) {
            if (random < rule.weight) return rule.structure;
            random -= rule.weight;
        }
        return rules[rules.length - 1].structure; // Fallback for floating point precision
    }

    // SECTION 3: MODULAR GENERATION & RENDERING
    // STRATEGIC JUSTIFICATION: Implements the "library of parametric generative modules" and the LOD system.
    // Each function draws an object, with appearance determined by seed and detail by zoom.

    function drawGlowParticle(ctx, x, y, radius, color, glowColor) {
        ctx.save();
        ctx.globalCompositeOperation = 'lighter'; // Additive blending for glow effect

        const grad = ctx.createRadialGradient(x, y, 0, x, y, radius);
        grad.addColorStop(0, `rgba(${color.r}, ${color.g}, ${color.b}, 1)`);
        grad.addColorStop(0.4, `rgba(${glowColor.r}, ${glowColor.g}, ${glowColor.b}, 0.5)`);
        grad.addColorStop(1, `rgba(${glowColor.r}, ${glowColor.g}, ${glowColor.b}, 0)`);

        ctx.fillStyle = grad;
        ctx.beginPath();
        ctx.arc(x, y, radius, 0, Math.PI * 2);
        ctx.fill();

        ctx.restore();
    }

    function drawStarSystem(ctx, seed, cx, cy, size, zoom) {
        const rng = new LCG(seed);
        const starType = rng.nextFloat();

        let starColor, glowColor;
        if (starType < 0.1) { starColor = { r: 170, g: 190, b: 255 }; glowColor = { r: 100, g: 120, b: 200 }; }
        else if (starType < 0.8) { starColor = { r: 255, g: 255, b: 200 }; glowColor = { r: 200, g: 200, b: 100 }; } 
        else { starColor = { r: 255, g: 180, b: 120 }; glowColor = { r: 200, g: 100, b: 50 }; }

        const radius = Math.max(0.5, size * 0.05);
        drawGlowParticle(ctx, cx, cy, radius, starColor, glowColor);

        // LOD: Draw planets only when zoomed in sufficiently
        const planetLOD = 0.01;
        if (size > width * planetLOD) {
            const numPlanets = Math.floor(rng.nextFloat() * 10);
            for (let i = 0; i < numPlanets; i++) {
                const angle = rng.nextFloat() * Math.PI * 2;
                // REFINEMENT: Use a power law for orbital distance to create more natural clustering near the star.
                const dist = (Math.pow(rng.nextFloat(), 2) * 0.4 + 0.1) * size;
                const planetX = cx + Math.cos(angle) * dist;
                const planetY = cy + Math.sin(angle) * dist;
                const planetRadius = Math.max(0.5, size * 0.005 * (0.5 + rng.nextFloat()));

                // REFINEMENT: Added color and alpha variation to planets for better aesthetics.
                const r = 100 + rng.nextFloat() * 100;
                const g = 100 + rng.nextFloat() * 100;
                const b = 100 + rng.nextFloat() * 100;
                ctx.fillStyle = `rgba(${r}, ${g}, ${b}, 0.9)`;
                ctx.beginPath();
                ctx.arc(planetX, planetY, planetRadius, 0, Math.PI * 2);
                ctx.fill();
            }
        }
    }

    function drawGalaxy(ctx, seed, cx, cy, size, zoom) {
        const impostorLOD = 0.05;
        if (size < width * impostorLOD) {
            drawGlowParticle(ctx, cx, cy, Math.max(1, size * 0.01), {r:200, g:200, b:255}, {r:150, g:150, b:255});
            return;
        }

        const rng = new LCG(seed);
        const numArms = 2 + Math.floor(rng.nextFloat() * 4);
        const armSpread = rng.nextFloat() * 0.5 + 0.5;

        // REFINEMENT: Star count now scales with on-screen size for better performance and visual consistency.
        const starCount = Math.min(2000, Math.floor(size * 1.5));
        const pixelSize = Math.max(1, 1 / zoom); // Ensure stars are visible when highly zoomed.

        for (let i = 0; i < starCount; i++) {
            const dist = rng.nextFloat() * (size / 2);
            const angle = rng.nextFloat() * Math.PI * 2;
            const arm = Math.floor(angle / (Math.PI * 2) * numArms);

            const spiralAngle = (arm * (Math.PI * 2 / numArms)) + Math.pow(dist / (size / 2), 0.5) * armSpread * 4;
            const starX = cx + Math.cos(spiralAngle) * dist;
            const starY = cy + Math.sin(spiralAngle) * dist;

            const brightness = 150 + Math.floor(rng.nextFloat() * 105);
            ctx.fillStyle = `rgb(${brightness}, ${brightness}, ${brightness})`;
            ctx.fillRect(starX, starY, pixelSize, pixelSize);
        }

        // REFINEMENT: Add a bright central core to the galaxy.
        drawGlowParticle(ctx, cx, cy, size * 0.1, {r:255, g:255, b:230}, {r:255, g:255, b:200});
    }

    function drawNebula(ctx, seed, cx, cy, size, zoom) {
        if (size < width * 0.02) { // LOD Impostor
            ctx.fillStyle = `rgba(130, 80, 180, 0.2)`;
            ctx.beginPath();
            ctx.arc(cx, cy, size/2, 0, Math.PI * 2);
            ctx.fill();
            return;
        }

        const rng = new LCG(seed);
        const numClouds = Math.max(10, Math.floor(size / 20)); // Scale cloud count with size
        ctx.save();
        ctx.globalCompositeOperation = 'lighter';
        for (let i = 0; i < numClouds; i++) {
            const x = cx + (rng.nextFloat() - 0.5) * size;
            const y = cy + (rng.nextFloat() - 0.5) * size;
            const radius = rng.nextFloat() * size * 0.3;

            const grad = ctx.createRadialGradient(x, y, 0, x, y, radius);
            // REFINEMENT: Added more color variance for richer nebula visuals.
            const r = 50 + rng.nextFloat() * 100;
            const g = 20 + rng.nextFloat() * 80;
            const b = 80 + rng.nextFloat() * 120;
            const alpha = 0.05 + rng.nextFloat() * 0.1;
            grad.addColorStop(0, `rgba(${r}, ${g}, ${b}, ${alpha})`);
            grad.addColorStop(1, `rgba(${r}, ${g}, ${b}, 0)`);

            ctx.fillStyle = grad;
            ctx.fillRect(x - radius, y - radius, radius * 2, radius * 2);
        }
        ctx.restore();
    }

    // REFINEMENT: New module for distant, unresolved clusters to prevent blank screen on zoom-out.
    function drawClusterImpostor(ctx, cx, cy, size) {
        ctx.fillStyle = `rgba(180, 180, 220, 0.05)`;
        ctx.beginPath();
        ctx.arc(cx, cy, size/2, 0, Math.PI*2);
        ctx.fill();
    }


    // SECTION 4: ON-DEMAND GENERATION ENGINE (SPATIAL PARTITIONING)
    // STRATEGIC JUSTIFICATION: This engine recursively subdivides space, applying grammar rules
    // to populate newly created regions only when they become visible.

    const MAX_DEPTH = 12;
    const MIN_NODE_SIZE_ON_SCREEN = 50;

    // REFINEMENT: Renamed class to Ninetree to accurately reflect its 3x3 subdivision, though it serves
    // the conceptual role of a Quadtree in this grammar-based system.
    class Ninetree {
        constructor(x, y, size, depth, symbol) {
            this.x = x; this.y = y; this.size = size; this.depth = depth; this.symbol = symbol;
            this.children = null;
            this.isPopulated = false;
            this.seed = this.calculateSeed();
        }

        calculateSeed() {
            // A robust integer hashing function to create a deterministic seed from position and depth.
            // This ensures the same part of space always generates the same content.
            let h1 = 0xdeadbeef, h2 = 0x41c6ce57;
            const s1 = Math.floor(this.x); const s2 = Math.floor(this.y); const s3 = this.depth;
            h1 = Math.imul(h1 ^ s1, 2654435761); h2 = Math.imul(h2 ^ s1, 1597334677);
            h1 = Math.imul(h1 ^ s2, 2654435761); h2 = Math.imul(h2 ^ s2, 1597334677);
            h1 = Math.imul(h1 ^ s3, 2654435761); h2 = Math.imul(h2 ^ s3, 1597334677);
            return (h1 ^ h2) >>> 0;
        }

        populateNode() {
            if (this.isPopulated || this.depth >= MAX_DEPTH) return;

            const rng = new LCG(this.seed);
            const structure = expandSymbol(this.symbol, rng);

            if (structure) {
                this.children = [];
                const childSize = this.size / 3;
                let structureIndex = 0;
                for (let i = 0; i < 3; i++) {
                    for (let j = 0; j < 3; j++) {
                        const childX = this.x + (j - 1) * childSize;
                        const childY = this.y + (i - 1) * childSize;
                        const childSymbol = structure[structureIndex++];
                        this.children.push(new Ninetree(childX, childY, childSize, this.depth + 1, childSymbol));
                    }
                }
            }
            this.isPopulated = true;
        }

        updateAndDraw(ctx, view, frustum) {
            // Frustum Culling: If node is not in view, do nothing.
            if (this.x + this.size / 2 < frustum.x1 || this.x - this.size / 2 > frustum.x2 ||
                this.y + this.size / 2 < frustum.y1 || this.y - this.size / 2 > frustum.y2) {
                return;
            }

            const sizeOnScreen = this.size * view.zoom;

            // LOD / Subdivision Logic: If node is large enough, subdivide and recurse.
            if (sizeOnScreen > MIN_NODE_SIZE_ON_SCREEN && this.depth < MAX_DEPTH) {
                if (!this.isPopulated) this.populateNode();
                if (this.children) {
                    for (const child of this.children) {
                        child.updateAndDraw(ctx, view, frustum);
                    }
                }
            } else { // Otherwise, render this node's content.
                const screenX = (this.x - view.x) * view.zoom + width / 2;
                const screenY = (this.y - view.y) * view.zoom + height / 2;

                switch(this.symbol) {
                    case 'S': drawStarSystem(ctx, this.seed, screenX, screenY, sizeOnScreen, view.zoom); break;
                    case 'G': drawGalaxy(ctx, this.seed, screenX, screenY, sizeOnScreen, view.zoom); break;
                    case 'N': drawNebula(ctx, this.seed, screenX, screenY, sizeOnScreen, view.zoom); break;
                    // REFINEMENT: Draw impostors for structural symbols when they are too small to expand.
                    case 'C': drawClusterImpostor(ctx, screenX, screenY, sizeOnScreen); break;
                }
            }
        }
    }

    // SECTION 5: MAIN APPLICATION LOOP
    // STRATEGIC JUSTIFICATION: Ties all components together, handling the continuous rendering loop,
    // updating the view state, and initiating the drawing process from the root node.

    const UNIVERSE_SIZE = 1e9;
    const root = new Ninetree(0, 0, UNIVERSE_SIZE, 0, 'U');

    const zoomLevelUI = document.getElementById('zoom-level');
    const coordsUI = document.getElementById('coords');

    function animate() {
        requestAnimationFrame(animate);

        // Smooth camera movement via linear interpolation (lerp).
        const lerpFactor = 0.1;
        view.zoom += (view.targetZoom - view.zoom) * lerpFactor;
        view.x += (view.targetX - view.x) * lerpFactor;
        view.y += (view.targetY - view.y) * lerpFactor;

        // Define the viewing frustum in world coordinates for culling.
        const frustum = {
            x1: view.x - (width / 2) / view.zoom, x2: view.x + (width / 2) / view.zoom,
            y1: view.y - (height / 2) / view.zoom, y2: view.y + (height / 2) / view.zoom
        };

        ctx.fillStyle = '#000000';
        ctx.fillRect(0, 0, width, height);

        // Start the recursive drawing process from the root node.
        root.updateAndDraw(ctx, view, frustum);

        // Update UI.
        zoomLevelUI.textContent = `Zoom: ${view.zoom.toExponential(2)}`;
        coordsUI.textContent = `Pos: (${Math.round(view.x)}, ${Math.round(view.y)})`;
    }

    animate();
    </script>
</body>
</html>
