        // =========================================================================
        function createStarfield() {
            const starLayers = document.querySelectorAll('.star-layer');
            starLayers.forEach((layer, index) => {
                let boxShadow = '';
                const starCount = 200 * (index + 1); // More stars on further layers
                const viewSize = Math.max(window.innerWidth, window.innerHeight) * 10 * (index + 1);

                for (let i = 0; i < starCount; i++) {
                    const x = (Math.random() - 0.5) * viewSize;
                    const y = (Math.random() - 0.5) * viewSize;
                    const size = Math.random() * 2;
                    const color = `rgba(255, 255, 255, ${Math.random() * 0.5 + 0.5})`;
                    boxShadow += `${x}px ${y}px 0px ${size}px ${color}, `;
                }
                layer.style.boxShadow = boxShadow.slice(0, -2);
            });
        }

        // =========================================================================
        // CORE LOGIC: Scene Management & Camera Control
        //
        // Justification: These functions form the heart of the "director".
        // 'moveToScene' reads from the script (Phase 1), finds the target POI
        // (Phase 2), and updates the CSS transform on the canvas to create the
        // cinematic "infinite zoom." The timing and narrative display are
        // precisely controlled here, executing the core of the sub-strategy.
        // 'playNextScene' implements the linear progression of the state machine.
        // =========================================================================
        function moveToScene(sceneIndex) {
            if (sceneIndex < 0 || sceneIndex >= script.length) return;

            state.currentSceneIndex = sceneIndex;
            const scene = script[sceneIndex];
            const targetElement = document.getElementById(scene.targetId);

            if (!targetElement) {
                console.error(`Target element with ID ${scene.targetId} not found.`);
                return;
            }

            // Read storyboard coordinates from data-* attributes
            const x = parseFloat(targetElement.dataset.x) || 0;
            const y = parseFloat(targetElement.dataset.y) || 0;
            const scale = scene.scale;

            // Calculate transform to center the target in the viewport
            const targetX = -x;
            const targetY = -y;

            // Apply the transform to the canvas, creating the zoom/pan effect
            canvas.style.transform = `scale(${scale}) translate(${targetX}px, ${targetY}px)`;

            // Update narrator text, with a delay for the camera movement to start
            narrator.classList.remove('visible');
            setTimeout(() => {
                narrator.innerHTML = scene.text;
                narrator.classList.add('visible');
                // Re-attach event listeners for deep dive triggers if they exist
                attachDeepDiveListeners();
            }, 1500); // Wait 1.5s into the transition
        }

        function playNextScene() {
            if (!state.isPlaying) return;

            const nextIndex = state.currentSceneIndex + 1;
            if (nextIndex < script.length) {
                moveToScene(nextIndex);
                // The transition duration itself acts as the timer
                // We'll set a timeout to advance to the next scene.
                // Duration should be longer than the CSS transition to allow reading.
                const sceneDuration = 8000; // 8 seconds per scene
                state.sceneTimeout = setTimeout(playNextScene, sceneDuration);
            } else {
                // End of documentary
                pauseExperience();
                state.currentSceneIndex = -1; // Reset for replay
            }
        }

        // =========================================================================
        // PHASE 3: INTERACTION - Control Handlers
        //
        // Justification: Implements the minimal interaction model. 'playExperience'
        // and 'pauseExperience' manage the state machine. 'togglePlayPause' wires
        // this logic to the UI button. This is a direct execution of the strategy's
        // interaction constraints.
        // =========================================================================
        function playExperience() {
            if (state.isPlaying) return;
            state.isPlaying = true;
            playPauseBtn.innerHTML = '&#10074;&#10074;'; // Pause symbol
            playNextScene();
        }

        function pauseExperience() {
            state.isPlaying = false;
            playPauseBtn.innerHTML = '&#9658;'; // Play symbol
            clearTimeout(state.sceneTimeout);
        }

        function togglePlayPause() {
            if (state.isPlaying) {
                pauseExperience();
            } else {
                playExperience();
            }
        }

        function jumpToChapter(index) {
            pauseExperience();
            // Need a slight delay to ensure the pause takes effect before moving
            setTimeout(() => {
                moveToScene(index);
            }, 100);
        }

        // =========================================================================
        // PHASE 3: INTERACTION - UI Generation & Deep Dive Panels
        //
        // Justification: The chapter navigation is generated dynamically from the
        // script object, ensuring it's always in sync with the content. The logic
        // for showing/hiding deep dive panels is also handled here, completing
        // the required interactive elements.
        // =========================================================================
        function createChapterNav() {
            script.forEach((scene, index) => {
                const button = document.createElement('button');
                button.textContent = scene.title;
                button.addEventListener('click', () => jumpToChapter(index));
                chapterNavContainer.appendChild(button);
            });
        }

        function attachDeepDiveListeners() {
            const triggers = document.querySelectorAll('.deep-dive-trigger');
            triggers.forEach(trigger => {
                trigger.addEventListener('click', (e) => {
                    e.stopPropagation();
                    const panelId = e.target.dataset.panelId;
                    const panel = document.getElementById(panelId);
                    if (panel) {
                        panel.classList.add('visible');
                        pauseExperience(); // Pause documentary when reading panel
                    }
                });
            });
        }

        function initializeDeepDivePanels() {
            const closeButtons = document.querySelectorAll('.close-btn');
            closeButtons.forEach(button => {
                button.addEventListener('click', (e) => {
                    const panelId = e.target.dataset.panelId;
                    const panel = document.getElementById(panelId);
                    if (panel) {
                        panel.classList.remove('visible');
                    }
                });
            });
        }

        // =========================================================================
        // INITIALIZATION
        //
        // Justification: The main execution entry point. It calls all setup
        // functions to prepare the experience. This ensures the application starts
        // in a clean, predictable state.
        // =========================================================================
        function init() {
            createStarfield();
            createChapterNav();
            initializeDeepDivePanels();
            playPauseBtn.addEventListener('click', togglePlayPause);

            // Initial welcoming state before play is pressed
            narrator.innerHTML = "The Universe awaits. Press play to begin your journey.";
            narrator.classList.add('visible');
            moveToScene(0); // Move to first scene without playing to set the stage
        }

        init();
    });

    /*
