        function moveToScene(sceneIndex) {
            if (sceneIndex < 0 || sceneIndex >= script.length) return;

            state.currentSceneIndex = sceneIndex;
            const scene = script[sceneIndex];
            const targetElement = document.getElementById(scene.targetId);

            if (!targetElement) {
                console.error(`Target element with ID ${scene.targetId} not found.`);
                return;
            }

            // Read storyboard coordinates from data-* attributes
            const x = parseFloat(targetElement.dataset.x) || 0;
            const y = parseFloat(targetElement.dataset.y) || 0;
            const scale = scene.scale;

            // Calculate transform to center the target in the viewport
            const targetX = -x;
            const targetY = -y;

            // Apply the transform to the canvas, creating the zoom/pan effect
            canvas.style.transform = `scale(${scale}) translate(${targetX}px, ${targetY}px)`;

            // Update narrator text, with a delay for the camera movement to start
            narrator.classList.remove('visible');
            setTimeout(() => {
                narrator.innerHTML = scene.text;
                narrator.classList.add('visible');
                // Re-attach event listeners for deep dive triggers if they exist
                attachDeepDiveListeners();
            }, 1500); // Wait 1.5s into the transition
        }

        function playNextScene() {
            if (!state.isPlaying) return;

            const nextIndex = state.currentSceneIndex + 1;
            if (nextIndex < script.length) {
                moveToScene(nextIndex);
                // The transition duration itself acts as the timer
                // We'll set a timeout to advance to the next scene.
                // Duration should be longer than the CSS transition to allow reading.
                const sceneDuration = 8000; // 8 seconds per scene
                state.sceneTimeout = setTimeout(playNextScene, sceneDuration);
            } else {
                // End of documentary
                pauseExperience();
                state.currentSceneIndex = -1; // Reset for replay
            }
        }

        // =========================================================================
        // PHASE 3: INTERACTION - Control Handlers
        //
        // Justification: Implements the minimal interaction model. 'playExperience'
        // and 'pauseExperience' manage the state machine. 'togglePlayPause' wires
        // this logic to the UI button. This is a direct execution of the strategy's
        // interaction constraints.
        // =========================================================================
        function playExperience() {
            if (state.isPlaying) return;
            state.isPlaying = true;
            playPauseBtn.innerHTML = '&#10074;&#10074;'; // Pause symbol
            playNextScene();
        }

        function pauseExperience() {
            state.isPlaying = false;
            playPauseBtn.innerHTML = '&#9658;'; // Play symbol
            clearTimeout(state.sceneTimeout);
        }

        function togglePlayPause() {
            if (state.isPlaying) {
                pauseExperience();
            } else {
                playExperience();
            }
        }

        function jumpToChapter(index) {
            pauseExperience();
            // Need a slight delay to ensure the pause takes effect before moving
            setTimeout(() => {
                moveToScene(index);
            }, 100);
        }

        // =========================================================================
        // PHASE 3: INTERACTION - UI Generation & Deep Dive Panels
        //
        // Justification: The chapter navigation is generated dynamically from the
