                const button = document.createElement('button');
                button.textContent = scene.title;
                button.addEventListener('click', () => jumpToChapter(index));
                chapterNavContainer.appendChild(button);
            });
        }

        function attachDeepDiveListeners() {
            const triggers = document.querySelectorAll('.deep-dive-trigger');
            triggers.forEach(trigger => {
                trigger.addEventListener('click', (e) => {
                    e.stopPropagation();
                    const panelId = e.target.dataset.panelId;
                    const panel = document.getElementById(panelId);
                    if (panel) {
                        panel.classList.add('visible');
                        pauseExperience(); // Pause documentary when reading panel
                    }
                });
            });
        }

        function initializeDeepDivePanels() {
            const closeButtons = document.querySelectorAll('.close-btn');
            closeButtons.forEach(button => {
                button.addEventListener('click', (e) => {
                    const panelId = e.target.dataset.panelId;
                    const panel = document.getElementById(panelId);
                    if (panel) {
                        panel.classList.remove('visible');
                    }
                });
            });
        }

        // =========================================================================
        // INITIALIZATION
        //
        // Justification: The main execution entry point. It calls all setup
        // functions to prepare the experience. This ensures the application starts
        // in a clean, predictable state.
        // =========================================================================
        function init() {
            createStarfield();
            createChapterNav();
            initializeDeepDivePanels();
            playPauseBtn.addEventListener('click', togglePlayPause);

            // Initial welcoming state before play is pressed
            narrator.innerHTML = "The Universe awaits. Press play to begin your journey.";
            narrator.classList.add('visible');
            moveToScene(0); // Move to first scene without playing to set the stage
        }

