            }
        ];

        // =========================================================================
        // CACHED DOM ELEMENTS, STATE, AND CONSTANTS
        // Justification: Caching DOM references improves performance. The 'state' object
        // forms the core of our linear state machine. Constants are derived from CSS
        // for a single source of truth on timing.
        // =========================================================================
        const canvas = document.getElementById('universe-canvas');
        const narrator = document.getElementById('narrator');
        const playPauseBtn = document.getElementById('play-pause-btn');
        const chapterNavContainer = document.getElementById('chapter-nav');

        const state = {
            isPlaying: false,
            currentSceneIndex: -1,
            sceneTimeout: null
        };

        const rootStyles = getComputedStyle(document.documentElement);
        const TRANSITION_SPEED_MS = parseFloat(rootStyles.getPropertyValue('--transition-speed').trim().replace('s', '')) * 1000;
        const NARRATION_READ_TIME_MS = 6000;
        const SCENE_DURATION_MS = TRANSITION_SPEED_MS + NARRATION_READ_TIME_MS;

        // =========================================================================
        // PHASE 2 & 4: PROCEDURAL CONTENT & ATMOSPHERE - Star Generation
        // Justification: Procedurally generates a robust starfield. By using a fixed,
        // large area for star distribution, the effect is consistent and performant
        // across all screen sizes, an improvement over viewport-dependent calculations.
        // =========================================================================
        function createStarfield() {
            const starLayers = document.querySelectorAll('.star-layer');
            const STAR_AREA_SIZE = 4000; 
            starLayers.forEach((layer, index) => {
                let boxShadow = '';
                const starCount = 250 * (index + 1);
                for (let i = 0; i < starCount; i++) {
                    const x = (Math.random() - 0.5) * STAR_AREA_SIZE;
                    const y = (Math.random() - 0.5) * STAR_AREA_SIZE;
                    const size = Math.random() * 2;
                    const color = `rgba(255, 255, 255, ${Math.random() * 0.5 + 0.5})`;
                    boxShadow += `${x.toFixed(2)}px ${y.toFixed(2)}px 0 ${size.toFixed(2)}px ${color}, `;
                }
                layer.style.boxShadow = boxShadow.slice(0, -2);
            });
        }

        // =========================================================================
        // CORE LOGIC (REFINED): Coordinate Resolution & Scene Management
        // Justification: This is the analytical heart of the director. The critical
        // `getAbsoluteCoords` function corrects a fundamental flaw by correctly
        // calculating the position of nested POIs. `moveToScene` uses this data to
        // precisely control the camera, fulfilling the core "infinite zoom" mechanic.
        // =========================================================================
        function getAbsoluteCoords(element) {
            let x = 0;
            let y = 0;
            let current = element;
            while (current && current.id !== 'universe-canvas') {
                if (current.classList.contains('poi')) {
                    x += parseFloat(current.dataset.x) || 0;
                    y += parseFloat(current.dataset.y) || 0;
                }
                current = current.parentElement;
            }
            return { x, y };
        }

        function moveToScene(sceneIndex) {
            if (sceneIndex < 0 || sceneIndex >= script.length) return;

            state.currentSceneIndex = sceneIndex;
            const scene = script[sceneIndex];
            const targetElement = document.getElementById(scene.targetId);

            if (!targetElement) {
                console.error(`Target element with ID ${scene.targetId} not found.`);
                return;
            }

            const { x, y } = getAbsoluteCoords(targetElement);
            const scale = scene.scale;

            canvas.style.transform = `scale(${scale}) translate(${-x}px, ${-y}px)`;

            narrator.classList.remove('visible');
            setTimeout(() => {
                narrator.innerHTML = scene.text;
                narrator.classList.add('visible');
            }, TRANSITION_SPEED_MS / 2);

            updateChapterNavUI(sceneIndex);
        }

        function playNextScene() {
            if (!state.isPlaying) return;

            const nextIndex = (state.currentSceneIndex + 1) % script.length;
            moveToScene(nextIndex);

            if (nextIndex === script.length - 1) { // Last scene
                state.sceneTimeout = setTimeout(() => {
                    pauseExperience();
                    state.currentSceneIndex = -1; // Reset for replay
                }, SCENE_DURATION_MS);
            } else {
                state.sceneTimeout = setTimeout(playNextScene, SCENE_DURATION_MS);
            }
        }

        // =========================================================================
        // PHASE 3: INTERACTION - Control Handlers & UI Management
        // Justification: Implements the minimal interaction model. Logic is separated
        // for clarity. The play/pause/chapter jump functions correctly manage the
        // state machine. The refined `updateChapterNavUI` provides essential user feedback.
        // =========================================================================
        function playExperience() {
            if (state.isPlaying) return;
            state.isPlaying = true;
            playPauseBtn.innerHTML = '&#10074;&#10074;';
            playPauseBtn.setAttribute('aria-label', 'Pause documentary');
            playNextScene();
        }

        function pauseExperience() {
            state.isPlaying = false;
            playPauseBtn.innerHTML = '&#9658;';
            playPauseBtn.setAttribute('aria-label', 'Play documentary');
            clearTimeout(state.sceneTimeout);
        }

        function togglePlayPause() {
            state.isPlaying ? pauseExperience() : playExperience();
        }

        function jumpToChapter(index) {
            pauseExperience();
            setTimeout(() => moveToScene(index), 100);
        }

        function updateChapterNavUI(activeIndex) {
            const buttons = chapterNavContainer.querySelectorAll('button');
            buttons.forEach((button, index) => {
                button.classList.toggle('active', index === activeIndex);
            });
        }

        // =========================================================================
        // PHASE 3 (REFINED): UI Generation & Event Delegation
        // Justification: Chapter navigation is generated dynamically from the script.
        // Event handling for deep dive panels now uses event delegation on the narrator
        // element, a more performant and robust pattern than re-attaching listeners.
        // =========================================================================
        function createChapterNav() {
            script.forEach((scene, index) => {
                const button = document.createElement('button');
                button.textContent = scene.title;
                button.className = 'ui-btn';
                button.addEventListener('click', () => jumpToChapter(index));
                chapterNavContainer.appendChild(button);
            });
        }

        function initializeInteraction() {
            playPauseBtn.addEventListener('click', togglePlayPause);

            // Event delegation for Deep Dive Triggers
            narrator.addEventListener('click', (e) => {
                if (e.target.matches('.deep-dive-trigger')) {
                    const panelId = e.target.dataset.panelId;
                    document.getElementById(panelId)?.classList.add('visible');
                    pauseExperience();
                }
            });

            // Event handler for all close buttons
            document.querySelectorAll('.close-btn').forEach(button => {
                button.addEventListener('click', (e) => {
                    const panelId = e.target.dataset.panelId;
                    document.getElementById(panelId)?.classList.remove('visible');
                });
            });
        }

        // =========================================================================
        // INITIALIZATION
        // Justification: The main execution entry point. Sets up a clean, predictable
        // initial state. The refined logic now sets a default wide view before the user
        // interacts, providing a better "establishing shot" for the documentary.
        // =========================================================================
        function init() {
            createStarfield();
            createChapterNav();
            initializeInteraction();

            // Set an initial, wide establishing shot of the galaxy
            const initialTarget = document.getElementById('poi-milkyway');
            const { x, y } = getAbsoluteCoords(initialTarget);
            canvas.style.transition = 'none'; // No transition for initial setup
            canvas.style.transform = `scale(0.02) translate(${-x}px, ${-y}px)`;
            setTimeout(() => canvas.style.transition = '', 50); // Re-enable transitions

            narrator.innerHTML = "The Universe awaits. Press play to begin your journey.";
            narrator.classList.add('visible');
        }

        init();
    });
</script>
</body>
</html>
