    </style>
</head>
<body>

    <!-- 
        Phase 1 & 2: Structural Elements (HTML)
        The HTML structure is minimal, serving as a scaffold for the dynamic experience.
        - `spaceCanvas`: The canvas for rendering the starfield (Phase 2).
        - `narrativeContainer` & `narrativeText`: The elements for displaying the Monomyth prompts (Phase 1).
        - `customCursor`: The visual representation of the user's point of interaction.
    -->
    <canvas id="spaceCanvas"></canvas>
    <div class="narrative-container">
        <p id="narrativeText" class="narrative-text"></p>
    </div>
    <div id="customCursor"></div>


    <script>
        //========================================================================================
        //  EXECUTION ENGINE INITIALIZATION
        //  This script is the core execution of the sub-strategy, integrating all phases.
        //========================================================================================

        //----------------------------------------------------------------------------------------
        //  SECTION 1: SETUP AND CONFIGURATION
        //  Establishment of the environment, variables, and constants that will govern the experience.
        //----------------------------------------------------------------------------------------

        // Step 1.1: Canvas and Rendering Context Initialization
        // Justification: Accessing the DOM elements defined in the HTML. The 2D rendering context
        // is the tool used to draw all visuals onto the canvas.
        const canvas = document.getElementById('spaceCanvas');
        const ctx = canvas.getContext('2d');
        const narrativeTextElement = document.getElementById('narrativeText');
        const customCursor = document.getElementById('customCursor');

        // Step 1.2: Global State and Configuration Variables
        // Justification: These variables define the fundamental parameters of the simulation.
        // They are declared at the top level for clarity and ease of modification.
        let width, height, centerX, centerY; // Canvas dimensions
        let stars = []; // Array to hold all star objects
        const STAR_COUNT = 2000; // Number of stars in the simulation
        let zoomSpeed = 0; // Initial zoom velocity, controlled by user input
        const ZOOM_FRICTION = 0.98; // A damping factor to make the zoom feel smoother
        let totalZoom = 0; // Cumulative zoom distance, used to trigger narrative stages

        // Step 1.3: Mouse position tracking for non-verbal choice
        // Justification: Required for Phase 3 interaction, specifically the 'follow the light'
        // vs 'enter the darkness' branching path.
        let mouseX = window.innerWidth / 2;
        let mouseY = window.innerHeight / 2;

        // Step 1.4: Narrative State Machine Configuration (Phase 1 & 3)
        // Justification: This object defines the structure of the Monomyth journey. Each stage
        // has a zoom threshold, a narrative text, and an `onEnter` function to trigger
        // specific visual or logical changes. This modular structure makes the narrative
        // flow explicit and manageable.
        const journey = {
            currentStage: -1, // Start before the first stage
            stages: [
                { // Stage 0: The Known World (Pre-Call)
                    threshold: 0,
                    text: "The familiar fades. A call echoes from the void. [Scroll to answer]",
                    onEnter: () => {
                        // At the very beginning, zoom is locked until the user scrolls.
                        zoomSpeed = 0;
                    }
                },
                { // Stage 1: The Call to Adventure (Leaving Earth)
                    threshold: 20, // Low threshold to begin the journey quickly
                    text: "To leave the shore is to trust the sea.",
                    onEnter: () => {
                        // The journey begins, stars are standard.
                        resetStarTypes('standard');
                    }
                },
                { // Stage 2: Tests, Allies, Enemies (Asteroid Field)
                    threshold: 300,
                    text: "Here, chaos is a path, not a barrier.",
                    onEnter: () => {
                        // Introduce a new visual element to represent the "test".
                        resetStarTypes('asteroids');
                        // Display visual cues for the non-verbal choice
                        journey.stages[2].choiceActive = true;
                    },
                    choiceActive: false,
                    choiceMade: null
                },
                { // Stage 3: The Inmost Cave / The Ordeal (Nebula)
                    threshold: 800,
                    text: "", // Text is determined by the choice in Stage 2
                    onEnter: () => {
                        // Determine the outcome of the non-verbal choice based on mouse position
                        const choice = (mouseX < width / 2) ? 'light' : 'darkness';
                        journey.stages[2].choiceMade = choice;
                        journey.stages[2].choiceActive = false;

                        if (choice === 'light') {
                            this.text = "Within the heart of creation, what do you find?";
                            resetStarTypes('nebula_light');
                        } else {
                            this.text = "In the silent abyss, what do you hear?";
                            resetStarTypes('nebula_dark');
                        }
                        // Update the text element directly since `this` context is tricky here
                        journey.stages[3].text = this.text;
                        updateNarrativeText(this.text);
                    }
                },
                { // Stage 4: The Return / Elixir (Contemplation)
                    threshold: 1500,
                    text: "The journey inward is the journey home.",
                    onEnter: () => {
                        // Return to a more serene visual state, signifying reflection.
                        resetStarTypes('serene');
                    }
                }
            ]
        };

        //----------------------------------------------------------------------------------------
        //  SECTION 2: CORE LOGIC AND DERIVATIONS
        //  Functions that form the engine of the simulation, including rendering, physics, and interaction.
        //----------------------------------------------------------------------------------------

        /**
         * Step 2.1: Star Object Definition
         * Justification: An object-oriented approach to represent each star. Each star is a point
         * in 3D space (x, y, z) and has a 2D projected position on the screen (sx, sy). This
         * encapsulates the state of each visual element.
         */
        function createStar() {
            return {
                x: (Math.random() - 0.5) * width * 2,
                y: (Math.random() - 0.5) * height * 2,
                z: Math.random() * width, // Start stars at varying depths
                pz: 0, // Previous z, for motion blur effect
                sx: 0, // Screen x
                sy: 0, // Screen y
                type: 'standard' // For visual variation between stages
            };
        }

        /**
         * Step 2.2: Perspective Projection Derivation and Implementation
         * Derivation: To create a 3D effect on a 2D canvas, we must project 3D coordinates (x, y, z)
         * onto a 2D plane. This is achieved using a simple perspective projection formula.
         * Assume the viewer's eye is at (0, 0, -focalLength). A point (x, y, z) in space will appear
         * on the screen at a position proportional to x/z and y/z.
         * A simplified formula for this is:
         *   scale = fieldOfView / (fieldOfView + z)
         *   screenX = (x * scale) + screenCenterX
         *   screenY = (y * scale) + screenCenterY
         * For this implementation, we simplify further for performance and aesthetic control:
         *   scale = fieldOfView / z
         * where `fieldOfView` is analogous to the camera's lens and canvas width.
         * This formula correctly makes objects appear smaller and move slower as `z` increases (further away).
         * Justification: This function is the mathematical core of the "infinite zoom" visual. It
         * updates each star's screen position based on its depth (z), creating the illusion of movement
         * through 3D space.
         */
        function projectStar(star) {
            const fieldOfView = width * 0.8;
            const scale = fieldOfView / star.z;
            star.sx = (star.x * scale) + centerX;
            star.sy = (star.y * scale) + centerY;
        }

        /**
         * Step 2.3: Drawing a single star
         * Justification: This function handles the visual representation of a star on the canvas.
         * The star's size and opacity are dependent on its `z` value, making distant stars smaller and fainter.
         * A "tail" is drawn from its previous position to its current one to create a motion blur effect,
         * which enhances the sensation of speed. Different `type` properties allow for varied visual
         * styles that align with the narrative stages (e.g., 'asteroids' are grey squares, 'nebula' stars are colored).
         */
        function drawStar(star) {
            if (star.z <= 0) return; // Do not draw if behind the camera

            const radius = (1 - star.z / width) * 2;
            if (radius <= 0) return; // Do not draw if too small to see

            let color;
            switch (star.type) {
                case 'asteroid':
                    color = `rgba(150, 150, 150, ${1 - star.z / width})`;
                    ctx.fillStyle = color;
                    ctx.fillRect(star.sx, star.sy, radius*2, radius*2);
                    break;
                case 'nebula_light':
                    color = `hsla(${200 + star.x/10}, 80%, 70%, ${1 - star.z / width})`; // Blues and cyans
                    ctx.fillStyle = color;
                    ctx.beginPath();
                    ctx.arc(star.sx, star.sy, radius, 0, Math.PI * 2);
                    ctx.fill();
                    break;
                case 'nebula_dark':
                    color = `hsla(${280 + star.x/10}, 80%, 60%, ${1 - star.z / width})`; // Purples and magentas
                    ctx.fillStyle = color;
                    ctx.beginPath();
                    ctx.arc(star.sx, star.sy, radius, 0, Math.PI * 2);
                    ctx.fill();
                    break;
                case 'serene':
                    color = `rgba(200, 220, 255, ${1 - star.z / width})`;
                    ctx.fillStyle = color;
                    ctx.beginPath();
                    ctx.arc(star.sx, star.sy, radius, 0, Math.PI * 2);
                    ctx.fill();
                    break;
                default: // 'standard'
                    // Motion blur effect
                    const prevScale = width * 0.8 / star.pz;
                    const prevX = (star.x * prevScale) + centerX;
                    const prevY = (star.y * prevScale) + centerY;

                    ctx.strokeStyle = `rgba(255, 255, 255, ${1 - star.z / width})`;
                    ctx.lineWidth = radius;
                    ctx.beginPath();
                    ctx.moveTo(prevX, prevY);
                    ctx.lineTo(star.sx, star.sy);
                    ctx.stroke();
            }
        }

        /**
         * Step 2.4: Displaying non-verbal choice cues
         * Justification: As part of Phase 3, this function provides the visual feedback for the
         * branching narrative choice. It draws subtle, glowing gradients on the left and right
         * sides of the screen, representing the 'light' and 'darkness' paths.
         */
        function drawChoiceCues() {
            // 'Light' cue on the left
            const lightGradient = ctx.createRadialGradient(width * 0.2, height / 2, 50, width * 0.2, height / 2, 300);
            lightGradient.addColorStop(0, 'rgba(180, 220, 255, 0.1)');
            lightGradient.addColorStop(1, 'rgba(180, 220, 255, 0)');
            ctx.fillStyle = lightGradient;
            ctx.fillRect(0, 0, width / 2, height);

            // 'Darkness' cue on the right
            const darkGradient = ctx.createRadialGradient(width * 0.8, height / 2, 50, width * 0.8, height / 2, 300);
            darkGradient.addColorStop(0, 'rgba(50, 0, 80, 0.1)');
            darkGradient.addColorStop(1, 'rgba(50, 0, 80, 0)');
            ctx.fillStyle = darkGradient;
            ctx.fillRect(width / 2, 0, width / 2, height);
        }

        /**
         * Step 2.5: Narrative Text Management
         * Justification: Handles the display and fading of the poetic fragments (Phase 1).
         * A simple mechanism prevents the same message from being re-triggered, and it controls
         * the CSS opacity property to create smooth transitions.
         */
        let lastDisplayedText = "";
        function updateNarrativeText(text) {
            if (text !== lastDisplayedText) {
                lastDisplayedText = text;
                narrativeTextElement.style.opacity = 0;
                // Use a timeout to allow the fade-out to be perceived before changing text
                setTimeout(() => {
                    narrativeTextElement.innerText = text;
                    narrativeTextElement.style.opacity = 1;
                }, 3000);
            }
        }

        //----------------------------------------------------------------------------------------
        //  SECTION 3: EVENT HANDLERS AND INITIALIZATION
        //  Code that connects the simulation to the user and the browser environment.
        //----------------------------------------------------------------------------------------

        /**
         * Step 3.1: Canvas Resizing
         * Justification: To ensure the experience remains immersive regardless of window size,
         * the canvas dimensions must be updated whenever the window is resized. All relevant
         * dimensional variables are recalculated.
         */
        function onResize() {
            width = canvas.width = window.innerWidth;
            height = canvas.height = window.innerHeight;
            centerX = width / 2;
            centerY = height / 2;
        }

        /**
         * Step 3.2: User Interaction Handler (Phase 3)
         * Justification: This is the core of the user agency mechanic. The 'wheel' event is captured
         * to modify the `zoomSpeed`. The change in speed is proportional to the scroll delta,
         * creating a responsive "push/pull" feeling. The value is clamped to prevent extreme speeds.
         */
        function onWheel(event) {
            // A small scroll delta should still create a noticeable effect.
            let delta = event.deltaY * -0.001;
            zoomSpeed += delta;
            // Clamp speed to prevent runaway values
            zoomSpeed = Math.max(-5, Math.min(5, zoomSpeed));

            // If at the very start, the first scroll "answers the call".
            if (journey.currentStage === 0) {
                 totalZoom = journey.stages[1].threshold; // Jump to the start of the first stage
            }
        }

        /**
         * Step 3.3: Mouse Movement Handler (Phase 3)
         * Justification: Tracks the mouse coordinates to update the custom cursor's position
         * and to provide the input for the non-verbal choice in narrative Stage 2.
         */
        function onMouseMove(event) {
            mouseX = event.clientX;
            mouseY = event.clientY;
            customCursor.style.left = mouseX + 'px';
            customCursor.style.top = mouseY + 'px';
        }

        /**
         * Step 3.4: Initialization Function
         * Justification: Sets up the entire experience. It calls the resize handler, populates
         * the initial starfield, and attaches the necessary event listeners.
         */
        function initialize() {
            window.addEventListener('resize', onResize);
            onResize(); // Call once to set initial size

            for (let i = 0; i < STAR_COUNT; i++) {
                stars.push(createStar());
            }

            document.addEventListener('wheel', onWheel);
            document.addEventListener('mousemove', onMouseMove);

            // Initial narrative setup
            journey.currentStage = 0;
            updateNarrativeText(journey.stages[0].text);
            journey.stages[0].onEnter();

            // Start the main animation loop
            requestAnimationFrame(animate);
        }

        /**
         * Step 3.5: Function to change star types during narrative transitions.
         * Justification: To reflect the changing tone of the Monomyth stages, this function
         * allows for a global change in the visual style of the particles.
         */
        function resetStarTypes(type) {
            stars.forEach(star => {
                star.type = type;
            });
        }


        //----------------------------------------------------------------------------------------
        //  SECTION 4: MAIN ANIMATION LOOP
        //  The heart of the application, running on every frame to update and render the scene.
        //----------------------------------------------------------------------------------------

        /**
         * Step 4.1: The `animate` function
         * Justification: This function is called recursively via `requestAnimationFrame` to create
         * a smooth animation. Its responsibilities are:
         * 1. Clear the canvas for the new frame. A low-opacity fill creates a trailing effect.
         * 2. Update simulation state: apply friction to zoom, update total zoom.
         * 3. Check for narrative stage transitions.
         * 4. Iterate through all stars: update their position, recycle if off-screen, project, and draw.
         * 5. Call itself for the next frame.
         */
        function animate() {
            // Fading background for motion trails effect
            ctx.fillStyle = 'rgba(0, 0, 0, 0.2)';
            ctx.fillRect(0, 0, width, height);

            // Update state
            zoomSpeed *= ZOOM_FRICTION; // Apply friction to slow down zoom gradually
            totalZoom += Math.abs(zoomSpeed); // Cumulative zoom always increases

            // Narrative State Machine Update (Phase 1 & 3)
            // Check if the next stage's threshold has been crossed.
            const nextStageIndex = journey.currentStage + 1;
            if (nextStageIndex < journey.stages.length && totalZoom >= journey.stages[nextStageIndex].threshold) {
                journey.currentStage = nextStageIndex;
                const stage = journey.stages[journey.currentStage];
                if (stage.onEnter) {
                    stage.onEnter();
                }
                // Don't update text for stage 3 here, as it's handled in onEnter
                if (journey.currentStage !== 3) {
                     updateNarrativeText(stage.text);
                }
            }

            // Update and draw all stars
            stars.forEach(star => {
                star.pz = star.z; // Store previous z for motion blur
                star.z -= zoomSpeed;

                // This logic creates the "infinite" field. If a star moves behind the camera
                // or too far away, it is recycled by placing it back at a random distant position.
                if (star.z < 1 || star.z > width * 2 || star.sx < 0 || star.sx > width || star.sy < 0 || star.sy > height) {
                    star.x = (Math.random() - 0.5) * width * 2;
                    star.y = (Math.random() - 0.5) * height * 2;
                    star.z = width + Math.random() * width; // Place it far away
                    star.pz = star.z;
                }

                projectStar(star);
                drawStar(star);
            });

            // Draw non-verbal choice cues if in the correct stage
            if (journey.stages[2].choiceActive) {
                drawChoiceCues();
            }

            requestAnimationFrame(animate);
        }

        // Start the experience
        initialize();

    </script>
</body>
</html>
```

