            }

            document.addEventListener('wheel', onWheel);
            document.addEventListener('mousemove', onMouseMove);

            // Initial narrative setup
            journey.currentStage = 0;
            updateNarrativeText(journey.stages[0].text);
            journey.stages[0].onEnter();

