        function projectStar(star) {
            // This implementation directly applies the formula derived in Section 1.
            const focalLength = width * 0.8; // 'f' in the derivation
            const scale = focalLength / star.z;
            star.sx = (star.x * scale) + centerX;
            star.sy = (star.y * scale) + centerY;
        }

        function drawStar(star) {
            if (star.z <= 0) return;
            const radius = Math.max(0, (1 - star.z / width) * 2.5);
            if (radius <= 0.1) return;

            let color;
            ctx.fillStyle = ctx.strokeStyle = color;

            // Standard motion blur stars
            if (star.type === 'standard' || star.type === 'serene') {
                const prevFocalLength = width * 0.8;
                const prevScale = prevFocalLength / star.pz;
                const prevX = (star.x * prevScale) + centerX;
                const prevY = (star.y * prevScale) + centerY;

                color = star.type === 'serene' ? `rgba(200, 220, 255, ${1 - star.z / width})` : `rgba(255, 255, 255, ${1 - star.z / width})`;
                ctx.strokeStyle = color;
                ctx.lineWidth = radius;
                ctx.beginPath();
                ctx.moveTo(prevX, prevY);
                ctx.lineTo(star.sx, star.sy);
                ctx.stroke();
