            if (text !== lastDisplayedText && text) {
                lastDisplayedText = text;
                narrativeTextElement.style.opacity = 0;
                setTimeout(() => {
                    narrativeTextElement.innerText = text;
                    narrativeTextElement.style.opacity = 1;
                }, 3000);
            }
        }

        function advanceJourney() {
            const current = journey.stages[journey.currentStage];
            if (current && current.onExit) {
                current.onExit(journey.stageState);
            }

            journey.currentStage++;
            const next = journey.stages[journey.currentStage];
            if (next) {
                // Reset state for the new stage
                journey.stageState = { ...journey.stageState, timeInStage: 0 };
                if (next.onEnter) {
                    next.onEnter(journey.stageState);
                }
                updateNarrativeText(next.text);
            }
        }

        function checkJourneyProgression(deltaTime) {
            journey.stageState.timeInStage += deltaTime;
            const stage = journey.stages[journey.currentStage];
            if (!stage) return;

            if (stage.onUpdate) {
                stage.onUpdate(journey.stageState);
            }

            if (stage.completionCondition && stage.completionCondition(journey.stageState)) {
                advanceJourney();
            }
        }

        //----------------------------------------------------------------------------------------
        //  SECTION 5: EVENT HANDLERS AND INITIALIZATION
        //----------------------------------------------------------------------------------------

        function onResize() {
            width = canvas.width = window.innerWidth;
            height = canvas.height = window.innerHeight;
            centerX = width / 2;
            centerY = height / 2;
        }

        function onWheel(event) {
            let delta = event.deltaY * -0.0015;
            zoomSpeed += delta;
            zoomSpeed = Math.max(-3, Math.min(3, zoomSpeed)); // Clamped speed
        }

        function onMouseMove(event) {
            mouseX = event.clientX;
            mouseY = event.clientY;
            customCursor.style.transform = `translate(${mouseX - 5}px, ${mouseY - 5}px)`;
        }

        function resetStarTypes(type) {
            stars.forEach(star => star.type = type);
        }

        function initialize() {
            window.addEventListener('resize', onResize);
            onResize();

            for (let i = 0; i < STAR_COUNT; i++) stars.push(createStar());

            document.addEventListener('wheel', onWheel);
            document.addEventListener('mousemove', onMouseMove);

            advanceJourney(); // Start the journey at Stage 0

            let lastTime = 0;
            function animationLoop(currentTime) {
                if (!lastTime) lastTime = currentTime;
                const deltaTime = currentTime - lastTime;
                lastTime = currentTime;

                animate(deltaTime); // Pass delta time to the main loop
                requestAnimationFrame(animationLoop);
            }
            requestAnimationFrame(animationLoop);
        }

        //----------------------------------------------------------------------------------------
        //  SECTION 6: MAIN ANIMATION LOOP
        //----------------------------------------------------------------------------------------

        function animate(deltaTime) {
            ctx.fillStyle = 'rgba(0, 0, 0, 0.25)';
            ctx.fillRect(0, 0, width, height);

            zoomSpeed *= Math.pow(ZOOM_FRICTION, deltaTime / 16.67); // Frame-rate independent friction

            checkJourneyProgression(deltaTime);

            stars.forEach(star => {
                star.pz = star.z;
                star.z -= zoomSpeed * (deltaTime / 16.67); // Frame-rate independent speed

                // Recycle stars for an infinite field
                if (star.z < 1 || star.z > width * 1.5 || star.sx < 0 || star.sx > width || star.sy < 0 || star.sy > height) {
                    star.x = (Math.random() - 0.5) * width * 2;
                    star.y = (Math.random() - 0.5) * height * 2;
                    star.z = width + Math.random() * (width * 0.5);
                    star.pz = star.z;
                }

                projectStar(star);
                drawStar(star);
            });

            if (journey.stageState.choiceActive) {
                drawChoiceCues();
            }
        }

