<body>

    <canvas id="spaceCanvas"></canvas>
    <div class="narrative-container">
        <p id="narrativeText" class="narrative-text"></p>
    </div>
    <div id="customCursor"></div>


    <script>
        //========================================================================================
        //  EXECUTION ENGINE INITIALIZATION
        //  This script is the core of the sub-strategy, integrating all phases into a cohesive
        //  interactive experience. It has been refined to align with the Knowledge Packet.
        //========================================================================================

        //----------------------------------------------------------------------------------------
        //  SECTION 1: MATHEMATICAL FOUNDATIONS & DERIVATIONS
        //  In adherence with the "ABSOLUTE PROHIBITION OF ASSUMPTIONS", the core rendering
        //  mathematics are derived here from first principles.
        //----------------------------------------------------------------------------------------

        /**
         * ## Derivation of Perspective Projection ##
         * 
         * GOAL: To project a point P(x, y, z) from a 3D coordinate system onto a 2D screen plane.
         * 
         * SETUP:
         * - Let the viewer's eye (the camera) be at the origin (0, 0, 0).
         * - Let the 2D screen plane be positioned at a distance `f` (the focal length) from the eye along the Z-axis.
         * - A point in 3D space is P = (x, y, z).
         * - The projected point on the 2D screen is P' = (sx, sy).
         * 
         * DERIVATION USING SIMILAR TRIANGLES:
         * 1.  Consider the projection from the side view (the Y-Z plane). We have two similar right-angled triangles:
         *     - The large triangle has vertices at the eye (0,0), the point's Z-coordinate on the Z-axis (0, z), and the point itself (y, z). Its height is `y` and its base is `z`.
         *     - The small triangle has vertices at the eye (0,0), the screen's position on the Z-axis (0, f), and the projected point on the screen (sy, f). Its height is `sy` and its base is `f`.
         * 
         * 2.  By the property of similar triangles, the ratio of corresponding sides is equal:
         *     sy / f = y / z
         * 
         * 3.  Solving for the screen coordinate `sy`:
         *     sy = (y * f) / z
         * 
         * 4.  Similarly, by looking from the top view (the X-Z plane), we can derive the screen coordinate `sx`:
         *     sx / f = x / z
         *     sx = (x * f) / z
         * 
         * 5.  CONCLUSION: The projection formula is (sx, sy) = ( (x*f)/z, (y*f)/z ).
         *     The term `f/z` can be seen as a `scale` factor. As `z` (distance) increases, the `scale` decreases,
         *     making objects appear smaller, which is the desired perspective effect. In this implementation,
         *     the `focalLength` (or `fieldOfView`) is coupled with the canvas width for aesthetic control.
         */


        //----------------------------------------------------------------------------------------
        //  SECTION 2: SETUP AND CONFIGURATION
        //----------------------------------------------------------------------------------------

        const canvas = document.getElementById('spaceCanvas');
        const ctx = canvas.getContext('2d');
        const narrativeTextElement = document.getElementById('narrativeText');
        const customCursor = document.getElementById('customCursor');

        let width, height, centerX, centerY;
        let stars = [];
        const STAR_COUNT = 2500;
        let zoomSpeed = 0;
        const ZOOM_FRICTION = 0.985; // Slightly increased friction for better control

        let mouseX = window.innerWidth / 2;
        let mouseY = window.innerHeight / 2;

        /**
         * ## Refined Narrative State Machine ##
         * Justification: The original state machine was based on `totalZoom`, a cumulative scroll distance,
         * which was identified as a flawed mechanic by Refuted Hypothesis #3. This new state machine
         * bases progression on completing interactive, thematic conditions (`completionCondition`),
         * ensuring the user's journey is one of agency, not passive observation.
         */
        const journey = {
            currentStage: -1,
            stages: [
                { // Stage 0: The Call to Adventure
                    text: "The familiar fades. A call echoes from the void. [Scroll to answer]",
                    onEnter: () => zoomSpeed = 0,
                    completionCondition: () => Math.abs(zoomSpeed) > 0.1, // Complete by starting to move
                },
                { // Stage 1: Leaving the Shore
                    text: "To leave the shore is to trust the sea.",
                    onEnter: () => resetStarTypes('standard'),
                    completionCondition: (state) => state.timeInStage > 8000, // Linger for 8 seconds
                },
                { // Stage 2: Tests, Allies, Enemies
                    text: "Here, chaos is a path, not a barrier. Choose...",
                    onEnter: (state) => {
                        resetStarTypes('asteroids');
                        state.choiceActive = true;
                        state.choiceFocus = 0; // Reset focus timer
                        state.focusTarget = null;
                    },
                    onUpdate: (state) => { // Per-frame logic for this stage
                        if (mouseX < width * 0.4) { // Left side focus
                            if (state.focusTarget !== 'light') { state.choiceFocus = 0; }
                            state.focusTarget = 'light';
                            state.choiceFocus += 1;
                        } else if (mouseX > width * 0.6) { // Right side focus
                            if (state.focusTarget !== 'darkness') { state.choiceFocus = 0; }
                            state.focusTarget = 'darkness';
                            state.choiceFocus += 1;
                        } else { // No focus
                            state.focusTarget = null;
                            state.choiceFocus = Math.max(0, state.choiceFocus - 2);
                        }
                    },
                    completionCondition: (state) => state.choiceFocus > 180, // Requires ~3 seconds of focus
                    onExit: (state) => {
                        state.choiceActive = false;
                        state.choiceMade = state.focusTarget;
                    }
                },
                { // Stage 3: The Inmost Cave / The Ordeal
                    text: "", // Determined by choice
                    onEnter: (state) => {
                        if (journey.stageState.choiceMade === 'light') {
                            this.text = "Within the heart of creation, what do you find?";
                            resetStarTypes('nebula_light');
                        } else {
                            this.text = "In the silent abyss, what do you hear?";
                            resetStarTypes('nebula_dark');
                        }
                        journey.stages[3].text = this.text; // Update definition for display
                        updateNarrativeText(this.text);
                    },
                    completionCondition: (state) => state.timeInStage > 12000 && Math.abs(zoomSpeed) < 0.2, // Linger then slow down to contemplate
                },
                { // Stage 4: The Return / Elixir
                    text: "The journey inward is the journey home.",
                    onEnter: () => resetStarTypes('serene'),
                    completionCondition: () => false, // Final stage, never completes
                }
            ],
            stageState: { timeInStage: 0 } // Holds dynamic state for the current stage
        };

        //----------------------------------------------------------------------------------------
        //  SECTION 3: CORE LOGIC AND RENDERING
        //----------------------------------------------------------------------------------------

        function createStar() {
            return {
                x: (Math.random() - 0.5) * width * 2,
                y: (Math.random() - 0.5) * height * 2,
                z: Math.random() * width,
                pz: 0, sx: 0, sy: 0,
                type: 'standard'
            };
        }

        function projectStar(star) {
            // This implementation directly applies the formula derived in Section 1.
            const focalLength = width * 0.8; // 'f' in the derivation
            const scale = focalLength / star.z;
            star.sx = (star.x * scale) + centerX;
            star.sy = (star.y * scale) + centerY;
        }

        function drawStar(star) {
            if (star.z <= 0) return;
            const radius = Math.max(0, (1 - star.z / width) * 2.5);
            if (radius <= 0.1) return;

            let color;
            ctx.fillStyle = ctx.strokeStyle = color;

            // Standard motion blur stars
            if (star.type === 'standard' || star.type === 'serene') {
                const prevFocalLength = width * 0.8;
                const prevScale = prevFocalLength / star.pz;
                const prevX = (star.x * prevScale) + centerX;
                const prevY = (star.y * prevScale) + centerY;

                color = star.type === 'serene' ? `rgba(200, 220, 255, ${1 - star.z / width})` : `rgba(255, 255, 255, ${1 - star.z / width})`;
                ctx.strokeStyle = color;
                ctx.lineWidth = radius;
                ctx.beginPath();
                ctx.moveTo(prevX, prevY);
                ctx.lineTo(star.sx, star.sy);
                ctx.stroke();
                return;
            }

            // Other particle types
            switch (star.type) {
                case 'asteroid':
                    color = `rgba(150, 150, 150, ${1 - star.z / width})`;
                    ctx.fillStyle = color;
                    ctx.fillRect(star.sx - radius, star.sy - radius, radius * 2, radius * 2);
                    break;
                case 'nebula_light':
                    color = `hsla(${200 + star.x / 10}, 80%, 70%, ${1 - star.z / width})`;
                    ctx.fillStyle = color;
                    break;
                case 'nebula_dark':
                    color = `hsla(${280 + star.x / 10}, 80%, 60%, ${1 - star.z / width})`;
                    ctx.fillStyle = color;
                    break;
            }
            ctx.beginPath();
            ctx.arc(star.sx, star.sy, radius, 0, Math.PI * 2);
            ctx.fill();
        }

        function drawChoiceCues() {
            const focusAmount = journey.stageState.choiceFocus / 180; // Normalize 0-1

            // 'Light' cue on the left
            const lightGradient = ctx.createRadialGradient(width * 0.2, height / 2, 50, width * 0.2, height / 2, 300);
            lightGradient.addColorStop(0, `rgba(180, 220, 255, ${0.1 + (journey.stageState.focusTarget === 'light' ? focusAmount * 0.2 : 0)})`);
            lightGradient.addColorStop(1, `rgba(180, 220, 255, 0)`);
            ctx.fillStyle = lightGradient;
            ctx.fillRect(0, 0, width / 2, height);

            // 'Darkness' cue on the right
            const darkGradient = ctx.createRadialGradient(width * 0.8, height / 2, 50, width * 0.8, height / 2, 300);
            darkGradient.addColorStop(0, `rgba(80, 0, 120, ${0.1 + (journey.stageState.focusTarget === 'darkness' ? focusAmount * 0.2 : 0)})`);
            darkGradient.addColorStop(1, `rgba(80, 0, 120, 0)`);
            ctx.fillStyle = darkGradient;
            ctx.fillRect(width / 2, 0, width / 2, height);

            // Draw focus indicator bar
            if (journey.stageState.focusTarget) {
                const barX = journey.stageState.focusTarget === 'light' ? width * 0.25 : width * 0.75;
                const barWidth = 100;
                ctx.fillStyle = 'rgba(255, 255, 255, 0.2)';
                ctx.fillRect(barX - barWidth/2, height - 30, barWidth, 3);
                ctx.fillStyle = 'rgba(255, 255, 255, 0.8)';
                ctx.fillRect(barX - barWidth/2, height - 30, barWidth * focusAmount, 3);
            }
        }

        //----------------------------------------------------------------------------------------
        //  SECTION 4: STATE MANAGEMENT & NARRATIVE PROGRESSION
        //----------------------------------------------------------------------------------------

        let lastDisplayedText = "";
        function updateNarrativeText(text) {
            if (text !== lastDisplayedText && text) {
                lastDisplayedText = text;
                narrativeTextElement.style.opacity = 0;
                setTimeout(() => {
                    narrativeTextElement.innerText = text;
                    narrativeTextElement.style.opacity = 1;
                }, 3000);
            }
        }

        function advanceJourney() {
            const current = journey.stages[journey.currentStage];
            if (current && current.onExit) {
                current.onExit(journey.stageState);
            }

            journey.currentStage++;
            const next = journey.stages[journey.currentStage];
            if (next) {
                // Reset state for the new stage
                journey.stageState = { ...journey.stageState, timeInStage: 0 };
                if (next.onEnter) {
                    next.onEnter(journey.stageState);
                }
                updateNarrativeText(next.text);
            }
        }

        function checkJourneyProgression(deltaTime) {
            journey.stageState.timeInStage += deltaTime;
            const stage = journey.stages[journey.currentStage];
            if (!stage) return;

            if (stage.onUpdate) {
                stage.onUpdate(journey.stageState);
            }

            if (stage.completionCondition && stage.completionCondition(journey.stageState)) {
                advanceJourney();
            }
        }

        //----------------------------------------------------------------------------------------
        //  SECTION 5: EVENT HANDLERS AND INITIALIZATION
        //----------------------------------------------------------------------------------------

        function onResize() {
            width = canvas.width = window.innerWidth;
            height = canvas.height = window.innerHeight;
            centerX = width / 2;
            centerY = height / 2;
        }

        function onWheel(event) {
            let delta = event.deltaY * -0.0015;
            zoomSpeed += delta;
            zoomSpeed = Math.max(-3, Math.min(3, zoomSpeed)); // Clamped speed
        }

        function onMouseMove(event) {
            mouseX = event.clientX;
            mouseY = event.clientY;
            customCursor.style.transform = `translate(${mouseX - 5}px, ${mouseY - 5}px)`;
        }

        function resetStarTypes(type) {
            stars.forEach(star => star.type = type);
        }

        function initialize() {
            window.addEventListener('resize', onResize);
            onResize();

            for (let i = 0; i < STAR_COUNT; i++) stars.push(createStar());

            document.addEventListener('wheel', onWheel);
            document.addEventListener('mousemove', onMouseMove);

            advanceJourney(); // Start the journey at Stage 0

            let lastTime = 0;
            function animationLoop(currentTime) {
                if (!lastTime) lastTime = currentTime;
                const deltaTime = currentTime - lastTime;
                lastTime = currentTime;

                animate(deltaTime); // Pass delta time to the main loop
                requestAnimationFrame(animationLoop);
            }
            requestAnimationFrame(animationLoop);
        }

        //----------------------------------------------------------------------------------------
        //  SECTION 6: MAIN ANIMATION LOOP
        //----------------------------------------------------------------------------------------

