        const mouseX = e.clientX - rect.left;
        const mouseY = e.clientY - rect.top;

        // Calculate world coordinates of the mouse pointer
        const worldX = camera.x + (mouseX - canvas.width / 2) / camera.zoom;
        const worldY = camera.y + (mouseY - canvas.height / 2) / camera.zoom;

        // Adjust zoom
        const zoomFactor = 1.1;
        const delta = e.deltaY > 0 ? 1 / zoomFactor : zoomFactor;
        const newZoom = Math.max(camera.minZoom, Math.min(camera.maxZoom, camera.zoom * delta));

        // Adjust camera position to keep the pointer over the same world coordinate
        camera.x = worldX - (mouseX - canvas.width / 2) / newZoom;
        camera.y = worldY - (mouseY - canvas.height / 2) / newZoom;
