                    if (!filters.allowedSpectralClasses.includes(spectralInfo.type)) continue;

                    const position = new THREE.Vector3(
                        (random.nextFloat() - 0.5) * cubeSize,
                        (random.nextFloat() - 0.5) * cubeSize,
                        (random.nextFloat() - 0.5) * cubeSize
                    ).add(cubeCenter);

                    // Create a unique, deterministic ID for each star.
                    const id = `star_${seed}_${i}`;

                    results.push({
                        id,
                        position: [position.x, position.y, position.z],
                        magnitude,
                        spectralClass: spectralInfo.type,
                        color: spectralInfo.color,
                        baseSize: (16 - magnitude) * 0.15,
                    });
                }
            }

            // Store result in cache.
            this.queryCache.set(cacheKey, { data: results, timestamp: Date.now() });

            // Documentation: A real backend would serialize this to a compact binary format
            // (e.g., Protocol Buffers, FlatBuffers, or custom binary layout) for network efficiency.
            // Example: [id_len, id_bytes, x_float, y_float, z_float, mag_float, class_byte, r_byte, g_byte, b_byte, ...]
            return results;
        }

        /**
         * Simulates fetching detailed information for a single object.
         * @param {string} objectId - The unique ID of the object.
         * @returns {Promise<object>} A promise resolving with detailed data.
         */
        async getDetails(objectId) {
            await new Promise(resolve => setTimeout(resolve, 50)); // Simulate latency

            // Re-generate the object's properties deterministically from its ID.
            const [_, seedStr, indexStr] = objectId.split('_');
            const seed = parseInt(seedStr, 10);
            const index = parseInt(indexStr, 10);

            const random = this.prng(seed);
            let magnitude, spectralInfo;
            // We must advance the PRNG to the correct state for this object.
            for (let i = 0; i <= index; i++) {
                magnitude = random.nextFloat() * 15 + 1;
                const spectralRoll = random.nextFloat();
                spectralInfo = this.SPECTRAL_CLASS_DISTRIBUTION.find(s => spectralRoll < s.cumulative);
            }

            return {
                id: objectId,
                name: `Star ${seed}-${index}`,
                spectralClass: spectralInfo.type,
                apparentMagnitude: magnitude.toFixed(2),
                temperature: (Math.pow(random.nextFloat(), 2) * 30000 + 2000).toFixed(0) + " K",
                distance: (Math.pow(random.nextFloat(), 3) * 5000 + 10).toFixed(2) + " ly",
                hasExoplanets: random.nextFloat() > 0.7 ? 'Yes' : 'No',
            };
        }
    }

    //------------------------------------------------------------------------------------------------
    // PHASE 3: ADVANCED INTERACTION AND UI DESIGN
    // Justification: This class isolates DOM manipulation and user input handling from the core
    // rendering and application logic. It directly implements the strategy's requirement for a
    // powerful UI that maps directly to API query parameters.
    //------------------------------------------------------------------------------------------------
    class UIController {
        constructor(onFilterChangeCallback) {
            this.magnitudeSlider = document.getElementById('magnitude-slider');
            this.magnitudeValue = document.getElementById('magnitude-value');
            this.spectralCheckboxes = document.querySelectorAll('.spectral-class');
            this.detailsPanel = document.getElementById('details-panel');
            this.detailsContent = document.getElementById('details-content');
            this.closeDetailsButton = document.getElementById('close-details');
            this.loadingIndicator = document.getElementById('loading-indicator');

            this.onFilterChange = onFilterChangeCallback;

            this.magnitudeSlider.addEventListener('input', this._handleFilterChange.bind(this));
            this.spectralCheckboxes.forEach(cb => cb.addEventListener('change', this._handleFilterChange.bind(this)));
            this.closeDetailsButton.addEventListener('click', () => this.hideDetails());

            this.updateMagnitudeLabel();
        }

        _handleFilterChange() {
            this.updateMagnitudeLabel();
            this.onFilterChange(this.getFilters());
        }

        getFilters() {
            const allowedSpectralClasses = Array.from(this.spectralCheckboxes)
                .filter(cb => cb.checked)
                .map(cb => cb.value);
            return {
                maxMagnitude: parseFloat(this.magnitudeSlider.value),
                allowedSpectralClasses,
            };
        }

        updateMagnitudeLabel() {
            this.magnitudeValue.textContent = `< ${parseFloat(this.magnitudeSlider.value).toFixed(1)}`;
        }

        showDetails(data) {
            this.detailsContent.innerHTML = `
                <p><strong>Designation:</strong> ${data.name}</p>
                <p><strong>Class:</strong> ${data.spectralClass}</p>
                <p><strong>Magnitude:</strong> ${data.apparentMagnitude}</p>
                <p><strong>Temperature:</strong> ${data.temperature}</p>
                <p><strong>Distance (est.):</strong> ${data.distance}</p>
                <p><strong>Exoplanets:</strong> ${data.hasExoplanets}</p>
            `;
            this.detailsPanel.classList.add('visible');
        }

        hideDetails() {
            this.detailsPanel.classList.remove('visible');
        }

        setLoading(isLoading) {
            this.loadingIndicator.classList.toggle('visible', isLoading);
        }
    }

    //------------------------------------------------------------------------------------------------
    // PHASE 2 & 4: DYNAMIC DATA-STREAMING CLIENT AND PERFORMANCE PLAN
    // Justification: This class is the core of the client application. It manages the WebGL scene,
    // camera, user controls, and orchestrates the data flow from the simulated server to the GPU.
    // It implements the full "details-on-demand" loop, object management, culling, and predictive
    // fetching as required by the strategy.
    //------------------------------------------------------------------------------------------------
    class StarField {
        constructor(container) {
            this.container = container;
            this.scene = new THREE.Scene();

            this.camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 10000);
            this.camera.position.z = 100;

            this.renderer = new THREE.WebGLRenderer({ antialias: true });
            this.renderer.setSize(window.innerWidth, window.innerHeight);
            this.renderer.setPixelRatio(window.devicePixelRatio);
            this.container.appendChild(this.renderer.domElement);

            this.controls = new OrbitControls(this.camera, this.renderer.domElement);
            this.controls.enableDamping = true;
            this.controls.dampingFactor = 0.05;
            this.controls.zoomSpeed = 2.0;
            this.controls.panSpeed = 0.5;
            this.controls.minDistance = 1;
            this.controls.maxDistance = 5000;

            this.api = new MockServerAPI();
            this.ui = new UIController(this.handleFilterChange.bind(this));

            this.raycaster = new THREE.Raycaster();
            this.pointer = new THREE.Vector2();
            this.raycaster.params.Points.threshold = 5; // Adjust threshold for easier clicking

            this.starPoints = null; // This will hold our THREE.Points object
            this.starData = new Map(); // Manages all star data by ID. { id: data }
            this.visibleStars = new Set(); // Manages IDs of stars currently in the GPU buffer.

            this.CUBE_SIZE = 500;
            this.lastCameraPosition = new THREE.Vector3();
            this.queryInProgress = false;
            this.needsUpdate = true;

            this.cameraVelocity = new THREE.Vector3();
            this.lastCameraUpdateTime = performance.now();

            this.initListeners();
            this.animate();
        }

        initListeners() {
            window.addEventListener('resize', this.onWindowResize.bind(this), false);
            this.controls.addEventListener('change', () => { this.needsUpdate = true; });
            window.addEventListener('click', this.onClick.bind(this), false);
        }

        onWindowResize() {
            this.camera.aspect = window.innerWidth / window.innerHeight;
            this.camera.updateProjectionMatrix();
            this.renderer.setSize(window.innerWidth, window.innerHeight);
        }

        handleFilterChange() {
            this.needsUpdate = true;
        }

        onClick(event) {
            // Calculate pointer position in normalized device coordinates (-1 to +1)
            this.pointer.x = (event.clientX / window.innerWidth) * 2 - 1;
            this.pointer.y = - (event.clientY / window.innerHeight) * 2 + 1;

            if (!this.starPoints) return;

            this.raycaster.setFromCamera(this.pointer, this.camera);
            const intersects = this.raycaster.intersectObject(this.starPoints);

            if (intersects.length > 0) {
                const intersection = intersects[0];
                const index = intersection.index;

                // Retrieve the ID of the clicked star from the geometry attribute
                const id = this.starPoints.geometry.attributes.customId.array[index];
                const star = this.starData.get(`star_${id}`);

                if (star) {
                    this.api.getDetails(star.id).then(details => {
                        this.ui.showDetails(details);
                    });
                }
            }
        }

        /**
         * Determines which spatial cubes need to be queried based on camera position and view distance.
         * Implements predictive fetching based on camera velocity.
         */
        getRequiredCubes() {
            const requiredCubes = new Set();
            const viewDistance = this.controls.getDistance() * 2; // Query a larger area than is visible
            const searchRadius = Math.ceil(Math.max(viewDistance, this.CUBE_SIZE) / this.CUBE_SIZE);
            const cameraCubePos = this.camera.position.clone().divideScalar(this.CUBE_SIZE).round();

            // Base query area around the camera
            for (let x = -searchRadius; x <= searchRadius; x++) {
                for (let y = -searchRadius; y <= searchRadius; y++) {
                    for (let z = -searchRadius; z <= searchRadius; z++) {
                        const cubePos = new THREE.Vector3(x, y, z).add(cameraCubePos).multiplyScalar(this.CUBE_SIZE);
                        requiredCubes.add(JSON.stringify(cubePos.toArray()));
                    }
                }
            }

            // Phase 4: Performance - Predictive Fetching
            // If the camera is moving fast enough, query cubes in the direction of movement.
            if (this.cameraVelocity.lengthSq() > 100) { // Threshold for significant movement
                const predictionFactor = 2; // How many radii ahead to look
                const predictionVector = this.cameraVelocity.clone().normalize().multiplyScalar(searchRadius * this.CUBE_SIZE * predictionFactor);
                const predictedCameraPos = this.camera.position.clone().add(predictionVector);
                const predictedCubePos = predictedCameraPos.divideScalar(this.CUBE_SIZE).round();

                for (let x = -searchRadius; x <= searchRadius; x++) {
                    for (let y = -searchRadius; y <= searchRadius; y++) {
                        for (let z = -searchRadius; z <= searchRadius; z++) {
                            const cubePos = new THREE.Vector3(x, y, z).add(predictedCubePos).multiplyScalar(this.CUBE_SIZE);
                            requiredCubes.add(JSON.stringify(cubePos.toArray()));
                        }
                    }
                }
            }

            return Array.from(requiredCubes).map(str => new THREE.Vector3().fromArray(JSON.parse(str)));
        }

        async updateSceneData() {
            if (this.queryInProgress) return;
            this.queryInProgress = true;
            this.ui.setLoading(true);

            const cubes = this.getRequiredCubes();
            const filters = this.ui.getFilters();

            try {
                const newStarDataArray = await this.api.query({ cubes, filters });
                const newStarIds = new Set();

                // Add new stars to the master data map.
                newStarDataArray.forEach(star => {
                    if (!this.starData.has(star.id)) {
                        this.starData.set(star.id, star);
                    }
                    newStarIds.add(star.id);
                });

                this.updateStarGeometry(newStarIds);

            } catch (error) {
                console.error("Failed to query mock server:", error);
            } finally {
                this.queryInProgress = false;
                this.ui.setLoading(false);
            }
        }

        /**
         * Rebuilds the THREE.Points geometry based on the set of star IDs that should be visible.
         * This is the core of the data streaming implementation.
         */
        updateStarGeometry(activeStarIds) {
            const starsToRender = Array.from(activeStarIds).map(id => this.starData.get(id));

            // If there are no stars, remove the points object.
            if (starsToRender.length === 0) {
                if (this.starPoints) {
                    this.scene.remove(this.starPoints);
                    this.starPoints.geometry.dispose();
                    this.starPoints.material.dispose();
                    this.starPoints = null;
                }
                return;
            }

            // Prepare attribute arrays.
            const positions = new Float32Array(starsToRender.length * 3);
            const colors = new Float32Array(starsToRender.length * 3);
            const sizes = new Float32Array(starsToRender.length);
            // Custom attribute to store a numeric representation of the star's ID for raycasting.
            const ids = new Float32Array(starsToRender.length);

            const tempColor = new THREE.Color();
            starsToRender.forEach((star, i) => {
                positions[i * 3] = star.position[0];
                positions[i * 3 + 1] = star.position[1];
                positions[i * 3 + 2] = star.position[2];

                tempColor.setHex(star.color);
                colors[i * 3] = tempColor.r;
                colors[i * 3 + 1] = tempColor.g;
                colors[i * 3 + 2] = tempColor.b;

                sizes[i] = star.baseSize;

                // Simple conversion from string ID "star_seed_index" to a single float.
                const [_, seedStr, indexStr] = star.id.split('_');
                ids[i] = parseFloat(`${seedStr}.${indexStr}`);
            });

            // If starPoints object doesn't exist, create it.
            if (!this.starPoints) {
                const geometry = new THREE.BufferGeometry();
                const material = new THREE.PointsMaterial({
                    size: 1, // Base size, will be scaled by attribute
                    vertexColors: true,
                    sizeAttenuation: true, // Stars farther away appear smaller
                    blending: THREE.AdditiveBlending,
                    transparent: true,
                    depthWrite: false, // Prevents artifacts with additive blending
                });
                // Attach shader logic to use the size attribute.
                material.onBeforeCompile = shader => {
                    shader.vertexShader = 'attribute float size;\n' + shader.vertexShader;
                    shader.vertexShader = shader.vertexShader.replace(
                        'gl_PointSize = size;',
                        'gl_PointSize = size * size;' // Use our custom size attribute
                    );
                };

                this.starPoints = new THREE.Points(geometry, material);
                this.scene.add(this.starPoints);
            }

            // Update geometry attributes.
            const geom = this.starPoints.geometry;
            geom.setAttribute('position', new THREE.BufferAttribute(positions, 3));
            geom.setAttribute('color', new THREE.BufferAttribute(colors, 3));
            geom.setAttribute('size', new THREE.BufferAttribute(sizes, 1));
            // Custom attribute for linking back to the original object ID
            geom.setAttribute('customId', new THREE.Float32Attribute(ids, 1)); 

            geom.attributes.position.needsUpdate = true;
            geom.attributes.color.needsUpdate = true;
            geom.attributes.size.needsUpdate = true;
            geom.attributes.customId.needsUpdate = true;
        }

        animate() {
            requestAnimationFrame(this.animate.bind(this));

            const now = performance.now();
            const delta = (now - this.lastCameraUpdateTime) / 1000;
            this.lastCameraUpdateTime = now;

            // Calculate camera velocity
            if (delta > 0) {
                this.cameraVelocity.subVectors(this.camera.position, this.lastCameraPosition).divideScalar(delta);
            }

            const distanceMoved = this.camera.position.distanceTo(this.lastCameraPosition);
            if (distanceMoved > this.CUBE_SIZE / 10) { // Trigger update if moved a significant distance
                this.needsUpdate = true;
            }

            if (this.needsUpdate) {
                this.updateSceneData();
                this.needsUpdate = false;
            }

            this.lastCameraPosition.copy(this.camera.position);

            this.controls.update();
            this.renderer.render(this.scene, this.camera);
        }
    }

    //------------------------------------------------------------------------------------------------
    // APPLICATION INITIALIZATION
    //------------------------------------------------------------------------------------------------
    const starField = new StarField(document.body);

    </script>
</body>
</html>
```

