    //------------------------------------------------------------------------------------------------
    // PHASE 1: SIMULATED BACKEND DATABASE AND API ARCHITECTURE
    // Justification: This class encapsulates the entire server-side logic as described in the 
    // sub-strategy. It simulates a database query through procedural generation, ensuring adherence to
    // the core architectural principle of a client-server model while respecting the standalone
    // file constraint.
    //------------------------------------------------------------------------------------------------
    class MockServerAPI {
        constructor() {
            // A simple PRNG for deterministic results based on a seed.
            // This is critical for making the universe feel persistent.
            this.prng = (seed) => {
                let s = seed % 2147483647;
                if (s <= 0) s += 2147483646;
                return {
                    next: () => s = s * 16807 % 2147483647,
                    nextFloat: () => (s = s * 16807 % 2147483647) / 2147483647,
                };
            };

            // Defines the distribution of stellar spectral classes. Based on real-world approximations.
            this.SPECTRAL_CLASS_DISTRIBUTION = [
                { type: 'O', cumulative: 0.0000003, color: 0x9bb0ff },
                { type: 'B', cumulative: 0.0013,    color: 0xaabfff },
                { type: 'A', cumulative: 0.0073,    color: 0xcad7ff },
                { type: 'F', cumulative: 0.0373,    color: 0xf8f7ff },
                { type: 'G', cumulative: 0.1133,    color: 0xfff4e8 },
                { type: 'K', cumulative: 0.2343,    color: 0xffddb4 },
                { type: 'M', cumulative: 0.999,     color: 0xffbd6f },
                { type: 'D', cumulative: 1.0,       color: 0xffffff }, // White Dwarfs
            ];

            // Server-side caching simulation as per strategy.
            // In a real system, this would be Redis or a similar in-memory store.
            this.queryCache = new Map();
            this.CACHE_TTL = 5000; // 5 seconds
        }

        /**
         * Simulates a spatial database query.
         * @param {object} params - The query parameters.
         * @param {Array<THREE.Vector3>} params.cubes - An array of cube center points to query.
         * @param {object} params.filters - Filtering criteria.
         * @returns {Promise<Array<object>>} A promise that resolves with an array of star data.
         */
        async query({ cubes, filters }) {
            // Simulate network latency.
            await new Promise(resolve => setTimeout(resolve, Math.random() * 250 + 50));

            const cacheKey = JSON.stringify({ cubes, filters });
            if (this.queryCache.has(cacheKey)) {
                const entry = this.queryCache.get(cacheKey);
                if (Date.now() - entry.timestamp < this.CACHE_TTL) {
                    return entry.data;
                }
            }

            let results = [];
            const cubeSize = 500; // The size of each queryable spatial cube.

            for (const cubeCenter of cubes) {
                // Generate a deterministic seed from the cube's coordinates.
                // This is the core of the persistent universe simulation.
                const seed = Math.floor(cubeCenter.x) ^ Math.floor(cubeCenter.y) << 11 ^ Math.floor(cubeCenter.z) << 22;
                const random = this.prng(seed);

                // Determine the number of stars in this cube.
                const starCount = Math.floor(random.nextFloat() * 150 + 50);

                for (let i = 0; i < starCount; i++) {
                    // Filter by apparent magnitude. Lower value = brighter.
                    const magnitude = random.nextFloat() * 15 + 1;
                    if (magnitude > filters.maxMagnitude) continue;

                    // Determine spectral class based on pre-defined distribution.
                    const spectralRoll = random.nextFloat();
                    const spectralInfo = this.SPECTRAL_CLASS_DISTRIBUTION.find(s => spectralRoll < s.cumulative);
                    if (!filters.allowedSpectralClasses.includes(spectralInfo.type)) continue;

                    const position = new THREE.Vector3(
                        (random.nextFloat() - 0.5) * cubeSize,
                        (random.nextFloat() - 0.5) * cubeSize,
                        (random.nextFloat() - 0.5) * cubeSize
                    ).add(cubeCenter);

                    // Create a unique, deterministic ID for each star.
                    const id = `star_${seed}_${i}`;

                    results.push({
                        id,
                        position: [position.x, position.y, position.z],
                        magnitude,
                        spectralClass: spectralInfo.type,
                        color: spectralInfo.color,
                        baseSize: (16 - magnitude) * 0.15,
                    });
                }
            }

            // Store result in cache.
            this.queryCache.set(cacheKey, { data: results, timestamp: Date.now() });

            // Documentation: A real backend would serialize this to a compact binary format
            // (e.g., Protocol Buffers, FlatBuffers, or custom binary layout) for network efficiency.
            // Example: [id_len, id_bytes, x_float, y_float, z_float, mag_float, class_byte, r_byte, g_byte, b_byte, ...]
            return results;
        }

        /**
         * Simulates fetching detailed information for a single object.
         * @param {string} objectId - The unique ID of the object.
         * @returns {Promise<object>} A promise resolving with detailed data.
         */
        async getDetails(objectId) {
            await new Promise(resolve => setTimeout(resolve, 50)); // Simulate latency

            // Re-generate the object's properties deterministically from its ID.
            const [_, seedStr, indexStr] = objectId.split('_');
            const seed = parseInt(seedStr, 10);
            const index = parseInt(indexStr, 10);

            const random = this.prng(seed);
            let magnitude, spectralInfo;
            // We must advance the PRNG to the correct state for this object.
            for (let i = 0; i <= index; i++) {
                magnitude = random.nextFloat() * 15 + 1;
                const spectralRoll = random.nextFloat();
                spectralInfo = this.SPECTRAL_CLASS_DISTRIBUTION.find(s => spectralRoll < s.cumulative);
            }

            return {
                id: objectId,
                name: `Star ${seed}-${index}`,
                spectralClass: spectralInfo.type,
                apparentMagnitude: magnitude.toFixed(2),
                temperature: (Math.pow(random.nextFloat(), 2) * 30000 + 2000).toFixed(0) + " K",
                distance: (Math.pow(random.nextFloat(), 3) * 5000 + 10).toFixed(2) + " ly",
                hasExoplanets: random.nextFloat() > 0.7 ? 'Yes' : 'No',
            };
        }
    }

    //------------------------------------------------------------------------------------------------
