            right: 20px;
            width: 300px;
            display: none;
        }
        #details-panel.visible {
            display: block;
        }
        #details-panel h3 {
            color: var(--glow-color);
            margin-bottom: 10px;
            border-bottom: 1px solid var(--border-color);
            padding-bottom: 5px;
        }
        #details-panel p {
            margin-bottom: 5px;
        }
        #details-panel strong {
            color: var(--glow-color);
            width: 120px;
            display: inline-block;
        }
