            const fragmentShader = `
                varying vec3 vWorldPosition;
                uniform vec3 u_cameraPosition;
                uniform float u_time;
                uniform vec3 u_nebulaColor1;
                uniform vec3 u_nebulaColor2;

                // --- 3D Simplex Noise Implementation (from a standard source) ---
                // This function generates procedural noise values based on a 3D coordinate.
                vec3 mod289(vec3 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
                vec4 mod289(vec4 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
                vec4 permute(vec4 x) { return mod289(((x*34.0)+1.0)*x); }
                vec4 taylorInvSqrt(vec4 r) { return 1.79284291400159 - 0.85373472095314 * r; }

                float snoise(vec3 v) {
                    const vec2 C = vec2(1.0/6.0, 1.0/3.0);
                    const vec4 D = vec4(0.0, 0.5, 1.0, 2.0);
                    vec3 i = floor(v + dot(v, C.yyy));
                    vec3 x0 = v - i + dot(i, C.xxx);
                    vec3 g = step(x0.yzx, x0.xyz);
                    vec3 l = 1.0 - g;
                    vec3 i1 = min(g.xyz, l.zxy);
                    vec3 i2 = max(g.xyz, l.zxy);
                    vec3 x1 = x0 - i1 + C.xxx;
                    vec3 x2 = x0 - i2 + C.yyy;
                    vec3 x3 = x0 - D.yyy;
                    i = mod289(i);
                    vec4 p = permute(permute(permute(
                        i.z + vec4(0.0, i1.z, i2.z, 1.0))
                        + i.y + vec4(0.0, i1.y, i2.y, 1.0))
                        + i.x + vec4(0.0, i1.x, i2.x, 1.0));
                    float n_ = 0.142857142857;
                    vec3 ns = n_ * D.wyz - D.xzx;
                    vec4 j = p - 49.0 * floor(p * ns.z * ns.z);
                    vec4 x_ = floor(j * ns.z);
                    vec4 y_ = floor(j - 7.0 * x_);
                    vec4 x = x_ * ns.x + ns.yyyy;
                    vec4 y = y_ * ns.x + ns.yyyy;
                    vec4 h = 1.0 - abs(x) - abs(y);
                    vec4 b0 = vec4(x.xy, y.xy);
                    vec4 b1 = vec4(x.zw, y.zw);
                    vec4 s0 = floor(b0) * 2.0 + 1.0;
                    vec4 s1 = floor(b1) * 2.0 + 1.0;
                    vec4 sh = -step(h, vec4(0.0));
                    vec4 a0 = b0.xzyw + s0.xzyw * sh.xxyy;
                    vec4 a1 = b1.xzyw + s1.xzyw * sh.zzww;
                    vec3 p0 = vec3(a0.xy, h.x);
                    vec3 p1 = vec3(a0.zw, h.y);
                    vec3 p2 = vec3(a1.xy, h.z);
                    vec3 p3 = vec3(a1.zw, h.w);
                    vec4 norm = taylorInvSqrt(vec4(dot(p0, p0), dot(p1, p1), dot(p2, p2), dot(p3, p3)));
                    p0 *= norm.x; p1 *= norm.y; p2 *= norm.z; p3 *= norm.w;
                    vec4 m = max(0.6 - vec4(dot(x0, x0), dot(x1, x1), dot(x2, x2), dot(x3, x3)), 0.0);
                    m = m * m;
                    return 42.0 * dot(m*m, vec4(dot(p0, x0), dot(p1, x1), dot(p2, x2), dot(p3, x3)));
                }

                // --- FBM (Fractal Brownian Motion) ---
                // Combines multiple layers (octaves) of noise for more detail.
                float fbm(vec3 p) {
                    float value = 0.0;
                    float amplitude = 0.5;
                    float frequency = 0.0;
                    for (int i = 0; i < 4; i++) {
                        value += amplitude * snoise(p);
                        p *= 2.0;
                        amplitude *= 0.5;
                    }
                    return value;
                }

                // Main raymarching logic
                void main() {
                    // 1. Define ray origin and direction
                    vec3 rayDir = normalize(vWorldPosition - u_cameraPosition);
                    vec3 rayOrigin = u_cameraPosition;

                    // 2. Perform ray-box intersection to find entry/exit points
                    // This is simplified for a box centered at origin
                    vec3 boxSize = vec3(300.0); // Must match geometry size
                    vec3 invRayDir = 1.0 / rayDir;
                    vec3 tMin = (-boxSize * 0.5 - rayOrigin) * invRayDir;
                    vec3 tMax = (boxSize * 0.5 - rayOrigin) * invRayDir;
                    vec3 t1 = min(tMin, tMax);
                    vec3 t2 = max(tMin, tMax);
                    float tNear = max(max(t1.x, t1.y), t1.z);
                    float tFar = min(min(t2.x, t2.y), t2.z);

                    if (tNear > tFar) {
                        // Ray misses the box entirely
                        discard;
                    }
                    tNear = max(tNear, 0.0);

                    // 3. Raymarch through the volume
                    vec4 accumulatedColor = vec4(0.0);
                    float accumulatedAlpha = 0.0;

                    int numSteps = 64; // Performance vs. Quality tradeoff
                    float stepSize = (tFar - tNear) / float(numSteps);

                    vec3 currentPos = rayOrigin + rayDir * (tNear + stepSize * 0.5);

                    for (int i = 0; i < numSteps; i++) {
                        if (accumulatedAlpha > 0.99) break; // Early termination

                        // 4. Sample the noise function at the current position
                        // Add time to make the nebula evolve
                        vec3 p = currentPos * 0.01 + vec3(u_time * 0.05);
                        float density = fbm(p);

                        // 5. Map noise value to color and density
                        if (density > 0.2) {
                            float densityFactor = (density - 0.2) / 0.8;
                            densityFactor = pow(densityFactor, 2.0) * 0.1;

                            // Mix between two colors based on another noise layer for variation
                            float colorNoise = snoise(p * 0.5);
                            vec3 color = mix(u_nebulaColor1, u_nebulaColor2, colorNoise);

                            // 6. Accumulate color and alpha using front-to-back compositing
                            float alpha = densityFactor * (1.0 - accumulatedAlpha);
                            accumulatedColor.rgb += color * alpha;
                            accumulatedAlpha += alpha;
                        }

                        currentPos += rayDir * stepSize;
                    }

                    gl_FragColor = vec4(accumulatedColor.rgb, accumulatedAlpha);
                }
            `;

