            // Point size is based on intrinsic size, zoom, and a base visibility minimum.
            // This is a key part of simulating LOD - brighter/larger stars remain visible longer.
            gl_PointSize = max(1.5, size * u_zoom * 0.05);

            v_z = position.z; // z is used for deterministic twinkle offset
        }
    `;

    const fragmentShaderSource = `
        precision mediump float;

        uniform float u_time;
        varying float v_z;

        void main() {
            // Soft, circular falloff for each point sprite.
            float dist = distance(gl_PointCoord, vec2(0.5, 0.5));
            if (dist > 0.5) {
                discard;
            }

            // Procedural twinkle effect
            // The sine function creates a smooth oscillation. v_z provides a unique offset
            // so stars don't all twinkle in unison.
            float twinkle = 0.8 + 0.2 * sin(u_time * 2.0 + v_z * 100.0);

            // Calculate final alpha with falloff and twinkle
            float alpha = (1.0 - smoothstep(0.4, 0.5, dist)) * twinkle;

            // Base color is white, but additive blending will create color mixes.
            gl_FragColor = vec4(1.0, 1.0, 1.0, alpha);
        }
    `;

    function createShader(gl, type, source) {
        const shader = gl.createShader(type);
        gl.shaderSource(shader, source);
        gl.compileShader(shader);
        if (!gl.getShaderParameter(shader, gl.COMPILE_STATUS)) {
            console.error('Shader compilation error:', gl.getShaderInfoLog(shader));
            gl.deleteShader(shader); return null;
        }
        return shader;
    }

    function createProgram(gl, vertexShader, fragmentShader) {
        const program = gl.createProgram();
        gl.attachShader(program, vertexShader);
        gl.attachShader(program, fragmentShader);
        gl.linkProgram(program);
        if (!gl.getProgramParameter(program, gl.LINK_STATUS)) {
            console.error('Program linking error:', gl.getProgramInfoLog(program));
            gl.deleteProgram(program); return null;
        }
        return program;
    }

    const vertexShader = createShader(gl, gl.VERTEX_SHADER, vertexShaderSource);
    const fragmentShader = createShader(gl, gl.FRAGMENT_SHADER, fragmentShaderSource);
    const program = createProgram(gl, vertexShader, fragmentShader);

    const dataAttribLocation = gl.getAttribLocation(program, 'a_data');
    const resolutionUniformLocation = gl.getUniformLocation(program, 'u_resolution');
    const offsetUniformLocation = gl.getUniformLocation(program, 'u_offset');
    const zoomUniformLocation = gl.getUniformLocation(program, 'u_zoom');
    const timeUniformLocation = gl.getUniformLocation(program, 'u_time');

    //----------------------------------------------------------------------------------------
    // Section 2: Simulated Offline Data Structuring & Tiling
    // STRATEGY ADHERENCE: This section is a direct, client-side simulation of the
    // "Pre-Processed Tiled Pyramid Approach". The procedural generation per cell, keyed by
    // coordinates, mimics fetching pre-processed data tiles. The `starCache` simulates
    // browser/service-worker caching of those tiles.
    //----------------------------------------------------------------------------------------

    function mulberry32(a) {
        return function() {
            let t = a += 0x6D2B79F5;
            t = Math.imul(t ^ t >>> 15, t | 1);
            t ^= t + Math.imul(t ^ t >>> 7, t | 61);
            return ((t ^ t >>> 14) >>> 0) / 4294967296;
        }
    }

    const TILE_SIZE = 5000;
    const starCache = new Map();
    const starDataForInteraction = new Map(); // Store full object data separately, keyed by tile key.

    function getCellKey(x, y) {
        return `${Math.floor(x / TILE_SIZE)}_${Math.floor(y / TILE_SIZE)}`;
    }

    function generateStarsForCell(cellX, cellY, zoom) {
        const key = `${cellX}_${cellY}`;
        if (starCache.has(key)) {
            return starCache.get(key);
        }

        const seed = cellX * 31415 + cellY * 92653;
        const random = mulberry32(seed);

        // Density increases with zoom level, simulating LOD.
        const density = 0.005 * Math.max(1, Math.log10(zoom * 100 + 1));
        const numStars = Math.floor(random() * (TILE_SIZE * TILE_SIZE * density));

        const starTypes = [
            { name: "O-type Supergiant", temp: "40,000K" }, { name: "B-type Giant", temp: "20,000K" },
            { name: "A-type Main-Sequence", temp: "8,500K" }, { name: "G-type Dwarf (Sun-like)", temp: "6,000K" },
            { name: "K-type Dwarf", temp: "4,500K" }, { name: "M-type Red Dwarf", temp: "3,000K" }
        ];

        const stars = [];
        const gpuData = new Float32Array(numStars * 4); // x, y, z, size

        for (let i = 0; i < numStars; i++) {
            const mag = 1.0 + random() * 6.0;
            const typeIndex = Math.floor(random() * starTypes.length);

            const star = {
                id: `VDB-${seed}-${i}`,
                x: cellX * TILE_SIZE + random() * TILE_SIZE,
                y: cellY * TILE_SIZE + random() * TILE_SIZE,
                z: random() * 1000,
                size: Math.pow(8 - mag, 2.5),
                mag: mag.toFixed(2),
                type: starTypes[typeIndex].name,
                temp: starTypes[typeIndex].temp
            };
            stars.push(star);

            const offset = i * 4;
            gpuData[offset + 0] = star.x;
            gpuData[offset + 1] = star.y;
            gpuData[offset + 2] = star.z;
            gpuData[offset + 3] = star.size;
        }

        starCache.set(key, gpuData);
        starDataForInteraction.set(key, stars);
        return gpuData;
    }

    //----------------------------------------------------------------------------------------
    // Section 3: Interaction, Rendering Loop, and Data Display
    // STRATEGY ADHERENCE: Implements the user interaction model (zoom/pan) which drives
    // the traversal of the simulated octree. The main render loop calculates the view
    // frustum, requests data tiles, and renders them. It also implements the "details-on-demand"
    // feature via a spatially-optimized click handler.
    // KNOWLEDGE INTEGRATION (REFUTED H3): The free-form exploration model aligns with the
    // knowledge that restrictive, scroll-based narratives are less engaging.
    //----------------------------------------------------------------------------------------
    const camera = { x: 0, y: 0, zoom: 0.05, minZoom: 0.0001, maxZoom: 200 };
    let isDragging = false;
    let lastMousePos = { x: 0, y: 0 };
    let needsDataUpdate = true;
    let visibleStarsCount = 0;

    const buffer = gl.createBuffer();
    gl.bindBuffer(gl.ARRAY_BUFFER, buffer);
    gl.enableVertexAttribArray(dataAttribLocation);
    gl.vertexAttribPointer(dataAttribLocation, 4, gl.FLOAT, false, 0, 0);

    function renderLoop(time) {
        if (canvas.width !== window.innerWidth || canvas.height !== window.innerHeight) {
            canvas.width = window.innerWidth;
            canvas.height = window.innerHeight;
            gl.viewport(0, 0, canvas.width, canvas.height);
            needsDataUpdate = true;
        }

        if (needsDataUpdate) {
            const viewWidth = canvas.width / camera.zoom;
            const viewHeight = canvas.height / camera.zoom;
            const startX = camera.x - viewWidth / 2;
            const startY = camera.y - viewHeight / 2;
            const endX = startX + viewWidth;
            const endY = startY + viewHeight;

            const startCellX = Math.floor(startX / TILE_SIZE);
            const startCellY = Math.floor(startY / TILE_SIZE);
            const endCellX = Math.floor(endX / TILE_SIZE);
            const endCellY = Math.floor(endY / TILE_SIZE);

            const visibleTilesData = [];
            let totalStars = 0;

            for (let cx = startCellX -1; cx <= endCellX + 1; cx++) {
                for (let cy = startCellY -1; cy <= endCellY + 1; cy++) {
                    const starsInCell = generateStarsForCell(cx, cy, camera.zoom);
                    visibleTilesData.push(starsInCell);
                    totalStars += starsInCell.length / 4;
                }
            }

            const combinedData = new Float32Array(totalStars * 4);
            let offset = 0;
            for(const tile of visibleTilesData) {
                combinedData.set(tile, offset);
                offset += tile.length;
            }

            gl.bindBuffer(gl.ARRAY_BUFFER, buffer);
            gl.bufferData(gl.ARRAY_BUFFER, combinedData, gl.DYNAMIC_DRAW);
            visibleStarsCount = totalStars;
            needsDataUpdate = false;
        }

        gl.clearColor(0.0, 0.0, 0.0, 1.0);
        gl.clear(gl.COLOR_BUFFER_BIT);
        gl.enable(gl.BLEND);
        gl.blendFunc(gl.SRC_ALPHA, gl.ONE);

        gl.useProgram(program);
        gl.uniform2f(resolutionUniformLocation, canvas.width, canvas.height);
        gl.uniform2f(offsetUniformLocation, camera.x, camera.y);
        gl.uniform1f(zoomUniformLocation, camera.zoom);
        gl.uniform1f(timeUniformLocation, time / 1000.0);

        gl.drawArrays(gl.POINTS, 0, visibleStarsCount);

        requestAnimationFrame(renderLoop);
    }

    // --- Event Listeners for Interaction ---
    canvas.addEventListener('wheel', e => {
        e.preventDefault();
        const rect = canvas.getBoundingClientRect();
        const mouseX = e.clientX - rect.left;
        const mouseY = e.clientY - rect.top;

        const worldX = camera.x + (mouseX - canvas.width / 2) / camera.zoom;
        const worldY = camera.y + (mouseY - canvas.height / 2) / camera.zoom;

        const zoomFactor = 1.1;
        const delta = e.deltaY > 0 ? 1 / zoomFactor : zoomFactor;
        const newZoom = Math.max(camera.minZoom, Math.min(camera.maxZoom, camera.zoom * delta));

        camera.x = worldX - (mouseX - canvas.width / 2) / newZoom;
        camera.y = worldY - (mouseY - canvas.height / 2) / newZoom;
        camera.zoom = newZoom;
        needsDataUpdate = true;
    }, { passive: false });

    canvas.addEventListener('mousedown', e => {
        isDragging = true;
        lastMousePos = { x: e.clientX, y: e.clientY };
        canvas.style.cursor = 'grabbing';
    });

    function stopDragging() {
        if (isDragging) {
            isDragging = false;
            canvas.style.cursor = 'grab';
        }
    }
    canvas.addEventListener('mouseup', stopDragging);
    canvas.addEventListener('mouseleave', stopDragging);

    canvas.addEventListener('mousemove', e => {
        if (isDragging) {
            const dx = e.clientX - lastMousePos.x;
            const dy = e.clientY - lastMousePos.y;
            camera.x -= dx / camera.zoom;
            camera.y -= dy / camera.zoom;
            lastMousePos = { x: e.clientX, y: e.clientY };
            needsDataUpdate = true;
        }
    });

    // --- "Details-on-demand" (Refined Implementation) ---
    // REFINEMENT: The search for the clicked star is now spatially optimized. Instead of a
    // brute-force search of all visible stars, it only considers stars in the clicked cell
    // and its immediate neighbors, more accurately simulating a quadtree/octree query.
    const infoPanel = document.getElementById('info-panel');
    canvas.addEventListener('click', e => {
        if (e.clientX !== lastMousePos.x || e.clientY !== lastMousePos.y) return;

        const rect = canvas.getBoundingClientRect();
        const clickWorldX = camera.x + (e.clientX - rect.left - canvas.width / 2) / camera.zoom;
        const clickWorldY = camera.y + (e.clientY - rect.top - canvas.height / 2) / camera.zoom;

        let closestStar = null;
        let minDistanceSq = Infinity;

        const clickedCellX = Math.floor(clickWorldX / TILE_SIZE);
        const clickedCellY = Math.floor(clickWorldY / TILE_SIZE);

        for (let cx = clickedCellX - 1; cx <= clickedCellX + 1; cx++) {
            for (let cy = clickedCellY - 1; cy <= clickedCellY + 1; cy++) {
                const key = `${cx}_${cy}`;
                if (starDataForInteraction.has(key)) {
                    for (const star of starDataForInteraction.get(key)) {
                        const dx = star.x - clickWorldX;
                        const dy = star.y - clickWorldY;
                        const distSq = dx * dx + dy * dy;
                        if (distSq < minDistanceSq) {
                            minDistanceSq = distSq;
                            closestStar = star;
                        }
                    }
                }
            }
        }

        const clickRadius = 20 / camera.zoom;
        if (closestStar && minDistanceSq < clickRadius * clickRadius) {
            document.getElementById('info-id').textContent = closestStar.id;
            document.getElementById('info-type').textContent = closestStar.type;
            document.getElementById('info-mag').textContent = closestStar.mag;
            document.getElementById('info-coords').textContent = `${closestStar.x.toFixed(0)}, ${closestStar.y.toFixed(0)}`;
            document.getElementById('info-temp').textContent = closestStar.temp;
            infoPanel.style.display = 'block';
        }
    });

    document.getElementById('close-panel').addEventListener('click', () => {
        infoPanel.style.display = 'none';
    });

    requestAnimationFrame(renderLoop);

    setTimeout(() => {
        const overlay = document.getElementById('title-overlay');
        overlay.style.transition = 'opacity 2s';
        overlay.style.opacity = '0';
        overlay.style.pointerEvents = 'none';
    }, 4000);

    </script>
</body>
