        const cataloguedStarsData = [
            { name: "Sol", type: "G-Type Main-Sequence (G2V)", position: new THREE.Vector3(0, 0, 0), description: "Our home star." },
            { name: "Proxima Centauri", type: "M-Type Red Dwarf (M5.5Ve)", position: new THREE.Vector3(2.5, -1.5, -3), description: "The closest known star to the Sun." },
            { name: "Sirius", type: "A-Type Main-Sequence (A1V)", position: new THREE.Vector3(-5, 4, -6), description: "The brightest star in the night sky." },
            { name: "Betelgeuse", type: "M-Type Red Supergiant (M1-2)", position: new THREE.Vector3(250, -300, 150), description: "A massive star nearing the end of its life." },
            { name: "Rigel", type: "B-Type Blue Supergiant (B8Ia)", position: new THREE.Vector3(-350, 100, -200), description: "A luminous supergiant in the Orion constellation." }
