            const positions = [];
            const colors = [];

            for (let i = 0; i < PROCEDURAL_STAR_COUNT; i++) {
                // Generate a random point with uniform volumetric distribution within a sphere.
                // The use of acos and cbrt is a mathematically sound method (inverse transform sampling)
                // to avoid clustering at the center and poles.
                const theta = 2 * Math.PI * Math.random();
                const phi = Math.acos(2 * Math.random() - 1);
                const r = PROCEDURAL_GENERATION_RADIUS * Math.cbrt(Math.random()); 

