            star.sx = (star.x * scale) + centerX;
            star.sy = (star.y * scale) + centerY;
        }

        function drawStar(star) {
            if (star.z <= 0) return;
            const radius = Math.max(0, (1 - star.z / width) * 2.5);
            if (radius <= 0.1) return;

            let color;
            ctx.fillStyle = ctx.strokeStyle = color;

            // Standard motion blur stars
            if (star.type === 'standard' || star.type === 'serene') {
                const prevFocalLength = width * 0.8;
                const prevScale = prevFocalLength / star.pz;
                const prevX = (star.x * prevScale) + centerX;
                const prevY = (star.y * prevScale) + centerY;

                color = star.type === 'serene' ? `rgba(200, 220, 255, ${1 - star.z / width})` : `rgba(255, 255, 255, ${1 - star.z / width})`;
                ctx.strokeStyle = color;
                ctx.lineWidth = radius;
                ctx.beginPath();
                ctx.moveTo(prevX, prevY);
                ctx.lineTo(star.sx, star.sy);
                ctx.stroke();
                return;
            }

            // Other particle types
            switch (star.type) {
                case 'asteroid':
                    color = `rgba(150, 150, 150, ${1 - star.z / width})`;
                    ctx.fillStyle = color;
                    ctx.fillRect(star.sx - radius, star.sy - radius, radius * 2, radius * 2);
                    break;
                case 'nebula_light':
                    color = `hsla(${200 + star.x / 10}, 80%, 70%, ${1 - star.z / width})`;
                    ctx.fillStyle = color;
                    break;
                case 'nebula_dark':
                    color = `hsla(${280 + star.x / 10}, 80%, 60%, ${1 - star.z / width})`;
                    ctx.fillStyle = color;
                    break;
            }
            ctx.beginPath();
            ctx.arc(star.sx, star.sy, radius, 0, Math.PI * 2);
            ctx.fill();
        }

        function drawChoiceCues() {
            const focusAmount = journey.stageState.choiceFocus / 180; // Normalize 0-1

            // 'Light' cue on the left
            const lightGradient = ctx.createRadialGradient(width * 0.2, height / 2, 50, width * 0.2, height / 2, 300);
            lightGradient.addColorStop(0, `rgba(180, 220, 255, ${0.1 + (journey.stageState.focusTarget === 'light' ? focusAmount * 0.2 : 0)})`);
            lightGradient.addColorStop(1, `rgba(180, 220, 255, 0)`);
            ctx.fillStyle = lightGradient;
            ctx.fillRect(0, 0, width / 2, height);

            // 'Darkness' cue on the right
            const darkGradient = ctx.createRadialGradient(width * 0.8, height / 2, 50, width * 0.8, height / 2, 300);
            darkGradient.addColorStop(0, `rgba(80, 0, 120, ${0.1 + (journey.stageState.focusTarget === 'darkness' ? focusAmount * 0.2 : 0)})`);
            darkGradient.addColorStop(1, `rgba(80, 0, 120, 0)`);
            ctx.fillStyle = darkGradient;
            ctx.fillRect(width / 2, 0, width / 2, height);

            // Draw focus indicator bar
            if (journey.stageState.focusTarget) {
                const barX = journey.stageState.focusTarget === 'light' ? width * 0.25 : width * 0.75;
                const barWidth = 100;
                ctx.fillStyle = 'rgba(255, 255, 255, 0.2)';
