        function advanceJourney() {
            const current = journey.stages[journey.currentStage];
            if (current && current.onExit) {
                current.onExit(journey.stageState);
            }

            journey.currentStage++;
            const next = journey.stages[journey.currentStage];
            if (next) {
                // Reset state for the new stage
                journey.stageState = { ...journey.stageState, timeInStage: 0 };
                if (next.onEnter) {
                    next.onEnter(journey.stageState);
                }
                updateNarrativeText(next.text);
            }
        }

        function checkJourneyProgression(deltaTime) {
            journey.stageState.timeInStage += deltaTime;
            const stage = journey.stages[journey.currentStage];
            if (!stage) return;

            if (stage.onUpdate) {
                stage.onUpdate(journey.stageState);
            }

            if (stage.completionCondition && stage.completionCondition(journey.stageState)) {
                advanceJourney();
            }
        }

        //----------------------------------------------------------------------------------------
        //  SECTION 5: EVENT HANDLERS AND INITIALIZATION
        //----------------------------------------------------------------------------------------

        function onResize() {
            width = canvas.width = window.innerWidth;
            height = canvas.height = window.innerHeight;
            centerX = width / 2;
            centerY = height / 2;
        }

        function onWheel(event) {
            let delta = event.deltaY * -0.0015;
            zoomSpeed += delta;
            zoomSpeed = Math.max(-3, Math.min(3, zoomSpeed)); // Clamped speed
        }

        function onMouseMove(event) {
